window.QUESTIONS.push(
  {"id":"sc-db-1","cat":"DB","level":"기본","q":"WHERE와 HAVING의 차이는 무엇이고, GROUP BY 없이도 HAVING을 쓸 수 있나요?","a":"SELECT 논리적 실행 순서가 FROM→WHERE→GROUP BY→HAVING→SELECT라서, WHERE는 그룹핑 전 개별 행을 거르고 HAVING은 그룹핑 후 집계 결과를 거릅니다. 그래서 WHERE에는 집계함수를 못 쓰고 HAVING에는 쓸 수 있습니다. GROUP BY가 없어도 전체를 한 그룹으로 보기 때문에 HAVING SUM(x) > 100 같은 식은 가능하지만, 단순 행 필터는 성능상 WHERE로 먼저 거르는 게 맞습니다."},
  {"id":"sc-db-2","cat":"DB","level":"중급","q":"NOT IN 서브쿼리에 NULL이 섞이면 결과가 비어버리는 이유는 무엇인가요?","a":"SQL은 3-valued logic이라 NULL과의 비교는 TRUE/FALSE가 아니라 UNKNOWN입니다. NOT IN (a, b, NULL)은 x<>a AND x<>b AND x<>NULL로 풀리는데 마지막 항이 항상 UNKNOWN이 되어 전체 AND가 절대 TRUE가 못 됩니다. 그래서 결과가 전부 빠집니다. 해결은 서브쿼리에서 NULL을 제외하거나 NOT EXISTS로 바꾸는 것이며, NOT EXISTS는 이 함정이 없습니다."},
  {"id":"sc-db-3","cat":"DB","level":"기본","q":"INNER JOIN과 LEFT JOIN의 결과 행 수가 같은 경우와 달라지는 경우를 설명해 주세요.","a":"오른쪽 테이블에 매칭되는 행이 모든 왼쪽 행에 대해 존재하면 INNER와 LEFT의 행 수가 같습니다. 매칭이 없는 왼쪽 행이 있으면 LEFT는 그 행을 NULL로 채워 유지하지만 INNER는 버려서 LEFT가 더 많아집니다. 반대로 오른쪽에 매칭이 여러 개면 둘 다 그만큼 행이 늘어납니다. '없는 것 찾기'는 LEFT JOIN + 오른쪽 키 IS NULL 패턴으로 합니다."},
  {"id":"sc-db-4","cat":"DB","level":"중급","q":"timestamp와 timestamptz의 차이는 무엇이고 어느 쪽을 기본으로 써야 하나요?","a":"timestamp는 타임존 정보 없이 벽시계 값만 저장하고, timestamptz는 입력을 UTC로 정규화해 저장하고 조회 시 세션 타임존으로 변환해 보여줍니다. 실제로 UTC 한 시점을 가리키므로 글로벌/다중 타임존 서비스에서는 timestamptz를 기본으로 쓰는 게 안전합니다. Django의 USE_TZ=True도 내부적으로 timestamptz와 맞물려 동작합니다."},
  {"id":"sc-db-5","cat":"DB","level":"기본","q":"char(n), varchar, text의 저장 방식·성능 차이와 PostgreSQL에서의 권장은 어떻게 되나요?","a":"char(n)은 고정 길이라 짧은 값도 공백으로 패딩하고, varchar(n)은 길이 제한이 있는 가변 길이, text는 제한 없는 가변 길이입니다. PostgreSQL에서는 셋의 내부 저장 방식과 성능이 사실상 동일하며 char의 패딩은 오히려 손해라, 보통 text 또는 varchar를 쓰고 길이 제약이 필요하면 varchar(n)이나 CHECK로 거는 걸 권장합니다."},
  {"id":"sc-db-6","cat":"DB","level":"중급","q":"2NF와 3NF의 차이를 부분 종속·이행 종속 개념으로 설명해 주세요.","a":"2NF는 복합 기본키의 일부에만 의존하는 부분 종속을 제거한 상태이고, 3NF는 기본키가 아닌 일반 컬럼이 다른 일반 컬럼을 거쳐 키에 의존하는 이행 종속을 제거한 상태입니다. 즉 2NF는 '키의 일부에 종속' 문제, 3NF는 '키가 아닌 것에 종속' 문제를 다룹니다. 모든 비키 속성이 키에만, 그것도 전체 키에만 직접 의존하면 3NF입니다."},
  {"id":"sc-db-7","cat":"DB","level":"중급","q":"반정규화는 무엇을 얻으려고 하는 것이고 어떤 비용을 치르나요?","a":"반정규화는 조인을 줄이고 읽기 성능을 높이려고 중복 데이터를 의도적으로 두는 것입니다. 대신 같은 값을 여러 곳에 두기 때문에 갱신 시 모든 사본을 맞춰야 하는 update anomaly와 정합성 관리 비용이 생깁니다. 그래서 읽기가 압도적으로 많고 정합성을 코드/배치로 보장할 수 있을 때 트레이드오프로 선택해야 합니다."},
  {"id":"sc-db-8","cat":"DB","level":"중급","q":"자연키 대신 대리키(surrogate key)를 쓰는 이유와 그 단점은 무엇인가요?","a":"대리키는 비즈니스 의미가 없는 인조 식별자(예: BigAutoField)라 값이 변하지 않고 단일 컬럼이라 조인·인덱스가 단순하다는 장점이 있습니다. 단점은 키 자체에 의미가 없어 자연키의 유일성 제약을 별도 UNIQUE로 또 걸어야 하고, 여분의 컬럼/인덱스가 생긴다는 점입니다. Spring/JPA의 @GeneratedValue(IDENTITY/SEQUENCE)가 Django의 BigAutoField에 대응됩니다."},
  {"id":"sc-db-9","cat":"DB","level":"중급","q":"FK 무결성을 DB 제약으로 거는 것과 애플리케이션에서만 관리하는 것의 트레이드오프는 무엇인가요?","a":"DB FK 제약은 어떤 경로로 들어와도 참조 무결성을 보장하고 ON DELETE 동작까지 위임할 수 있지만, 쓰기마다 검사·락 비용이 들고 샤딩 환경에선 강제가 어렵습니다. 앱에서만 관리하면 유연하고 성능 제어가 쉽지만 버그·동시성·다중 작성자 상황에서 깨진 참조가 생길 수 있습니다. 단일 RDB라면 DB 제약을 두는 게 안전한 기본값입니다."},
  {"id":"sc-db-10","cat":"DB","level":"기본","q":"N:M 관계를 관계형 DB와 ORM에서 각각 어떻게 매핑하나요?","a":"RDB에서는 N:M을 직접 표현할 수 없어 두 테이블의 FK를 가진 중간(연결) 테이블로 풀어냅니다. Django는 ManyToManyField가 이 중간 테이블을 자동 생성하고, 추가 컬럼이 필요하면 through= 모델로 명시합니다. JPA에서는 @ManyToMany + @JoinTable이 대응되며, 마찬가지로 부가 속성이 필요하면 연결 엔티티를 직접 만듭니다."},
  {"id":"sc-db-11","cat":"DB","level":"심화","q":"B-Tree와 B+Tree의 차이는 무엇이고, DB 인덱스가 B+Tree를 쓰는 이유는 무엇인가요?","a":"B-Tree는 내부 노드에도 데이터를 두지만, B+Tree는 실제 데이터(또는 포인터)를 리프에만 두고 리프들을 연결 리스트로 잇습니다. 덕분에 내부 노드에 키를 더 많이 담아 트리 높이가 낮아져 I/O가 적고, 리프가 정렬·연결돼 있어 범위 스캔과 정렬이 효율적입니다. 디스크 기반 DB에서 적은 I/O와 range scan이 핵심이라 B+Tree를 씁니다."},
  {"id":"sc-db-12","cat":"DB","level":"심화","q":"복합 인덱스 (a,b,c)가 있을 때 WHERE b=? AND c=? 쿼리가 인덱스를 제대로 못 타는 이유는 무엇인가요?","a":"복합 인덱스는 선두 컬럼부터 정렬되므로 leftmost prefix 규칙을 따릅니다. a / (a,b) / (a,b,c) 조합은 타지만, 선두 a 없이 b·c만 주면 인덱스 정렬 순서를 활용할 수 없어 효율적으로 못 탑니다. 또 a에 등호, 범위 조건은 뒤쪽에 두는 게 좋고, 범위 조건 이후 컬럼은 정렬 효과가 끊깁니다."},
  {"id":"sc-db-13","cat":"DB","level":"심화","q":"PostgreSQL의 인덱스는 클러스터드 인덱스인가요? MySQL InnoDB와의 차이를 설명해 주세요.","a":"PostgreSQL은 항상 논클러스터드입니다. 데이터는 heap에 들어가고 인덱스는 ctid(물리 위치)를 가리키며, CLUSTER 명령은 그 시점 한 번 물리 정렬만 하고 이후 유지되지 않습니다. 반면 MySQL InnoDB는 기본키가 곧 클러스터드 인덱스라 데이터가 PK 순서로 리프에 저장되고, 보조 인덱스는 PK를 거쳐 두 번 조회됩니다."},
  {"id":"sc-db-14","cat":"DB","level":"심화","q":"LIKE '%abc'처럼 앞에 와일드카드가 오는 검색이 인덱스를 못 타는데, 어떻게 해결하나요?","a":"B-Tree 인덱스는 앞에서부터 정렬돼 있어 선두가 고정돼야 범위를 좁힐 수 있는데, 선행 와일드카드는 시작 값을 모르므로 인덱스를 못 탑니다. 해결책은 컬럼을 뒤집어 저장한 reverse 인덱스(접미사 검색을 접두사 검색으로 변환), trigram(pg_trgm) GIN 인덱스, 또는 전문검색(GIN/tsvector)을 쓰는 것입니다. 묵시적 형변환이나 함수로 감싼 컬럼도 같은 이유로 인덱스를 깨뜨립니다."},
  {"id":"sc-db-15","cat":"DB","level":"심화","q":"커버링 인덱스와 Index Only Scan은 무엇이며, 인덱스만으로 항상 끝나지 않는 이유는 무엇인가요?","a":"커버링 인덱스는 쿼리가 필요로 하는 컬럼을 인덱스(INCLUDE 컬럼 포함)가 모두 담고 있어 heap을 안 보고 인덱스만 읽는 Index Only Scan이 가능한 경우입니다. 다만 PostgreSQL은 MVCC상 행의 가시성(visibility) 정보를 인덱스에 두지 않아 visibility map에서 해당 페이지가 all-visible이 아니면 heap을 확인해야 합니다. 그래서 VACUUM이 안 돌면 Index Only Scan이 보장되지 않습니다."},
  {"id":"sc-db-16","cat":"DB","level":"심화","q":"성별처럼 카디널리티가 낮은 컬럼 인덱스는 보통 무의미한데, 그래도 유효해지는 경우가 있나요?","a":"선택성이 낮으면 인덱스로 걸러도 대부분의 행이 남아 옵티마이저가 Seq Scan을 택하므로 단독 인덱스는 효과가 적습니다. 하지만 조회가 특정 값 한쪽에 치우치고 그 값의 비율이 작으면, 그 조건만 인덱싱하는 Partial Index(예: WHERE is_deleted=false)로 크기를 줄이고 효율을 낼 수 있습니다. 또 다른 고선택성 컬럼과 묶은 복합 인덱스의 후행 컬럼으로는 의미가 있습니다."},
  {"id":"sc-db-17","cat":"DB","level":"심화","q":"격리수준은 내부적으로 어떻게 구현되며, 수준을 높일수록 무엇을 잃게 되나요?","a":"격리는 락 기반(낮은 수준은 짧게, 높은 수준은 길게/범위까지 잠금)이나 MVCC 스냅샷, PostgreSQL의 SERIALIZABLE처럼 SSI로 구현됩니다. 수준을 높이면 Dirty/Non-repeatable/Phantom Read 같은 이상현상이 차단되는 대신 락 경합·재시도(serialization failure)·대기가 늘어 동시성과 처리량이 떨어집니다. 즉 정합성과 성능의 트레이드오프입니다."},
  {"id":"sc-db-18","cat":"DB","level":"심화","q":"MVCC가 '읽기가 쓰기를 막지 않게' 하는 원리와, 그래서 VACUUM이 필요한 이유를 설명해 주세요.","a":"MVCC는 각 행에 xmin/xmax 버전을 두고 트랜잭션 스냅샷 시점에 보이는 버전을 읽게 합니다. 그래서 읽는 쪽은 옛 버전을, 쓰는 쪽은 새 버전을 만들어 서로 블로킹하지 않습니다. 대신 UPDATE/DELETE가 옛 버전을 dead tuple로 남기므로 VACUUM이 이를 회수해 공간 비대(bloat)와 XID wraparound를 막아야 합니다. Oracle/MySQL은 undo segment로 옛 버전을 별도 관리한다는 차이가 있습니다."},
  {"id":"sc-db-19","cat":"DB","level":"심화","q":"PostgreSQL의 기본 격리수준은 무엇이고, PG의 REPEATABLE READ가 표준과 다른 점은 무엇인가요?","a":"PostgreSQL 기본은 READ COMMITTED라 매 구문마다 새 스냅샷을 떠 non-repeatable read가 가능합니다. 표준 REPEATABLE READ는 phantom read를 허용하지만, PG의 RR은 트랜잭션 시작 스냅샷을 끝까지 유지하는 MVCC라 phantom까지 막습니다. SERIALIZABLE은 SSI로 직렬성을 보장하되 충돌 시 serialization failure를 던져 재시도가 필요합니다."},
  {"id":"sc-db-20","cat":"DB","level":"중급","q":"비관적 락과 낙관적 락은 언제 선택하며, ORM에서는 각각 어떻게 구현하나요?","a":"충돌이 잦고 충돌 비용이 크면 비관적 락으로 미리 행을 잠가 대기시키고, 충돌이 드물면 낙관적 락으로 version 컬럼을 두고 커밋 시 버전 불일치면 재시도합니다. 비관적은 안전하지만 경합·데드락 위험이, 낙관적은 동시성은 좋지만 충돌 시 재시도 로직이 필요합니다. Django는 select_for_update()(비관)와 수동 version 비교(낙관), JPA는 @Lock(PESSIMISTIC)과 @Version에 대응됩니다."},
  {"id":"sc-db-21","cat":"DB","level":"중급","q":"데드락이 성립하는 4가지 조건과 현실적으로 데드락을 줄이는 방법은 무엇인가요?","a":"상호배제, 점유와 대기, 비선점, 순환대기가 모두 성립할 때 데드락이 발생합니다. 현실에서는 순환대기를 깨는 게 가장 실용적이라, 모든 트랜잭션이 자원을 같은 순서로 잠그도록 락 순서를 통일합니다. 그 외 락 보유 시간 단축, lock timeout, DB의 자동 데드락 detection으로 한쪽을 victim으로 롤백하는 방식을 함께 씁니다."},
  {"id":"sc-db-22","cat":"DB","level":"심화","q":"Spring의 @Transactional(REQUIRES_NEW)에 해당하는 Django 동작은 무엇이고, 영속성 컨텍스트 측면의 차이는 무엇인가요?","a":"REQUIRES_NEW는 기존 트랜잭션을 보류하고 독립 트랜잭션을 새로 여는 전파인데, Django에는 직접 대응이 없고 보통 분리된 transaction.atomic() 블록이나 중첩 savepoint로 흉내 냅니다. 더 결정적인 차이는 JPA가 1차 캐시·flush·dirty checking을 가진 영속성 컨텍스트로 동작하는 반면, Django ORM은 1차 캐시와 자동 dirty checking이 없어 변경을 save()로 명시해야 한다는 점입니다."},
  {"id":"sc-db-23","cat":"DB","level":"심화","q":"중복 결제(이른바 따닥)를 DB 레벨에서 차단하는 방법을 설명해 주세요.","a":"세 가지를 함께 씁니다. 첫째 결제 식별자에 UNIQUE 제약을 걸어 중복 INSERT를 DB가 막게 하고, 둘째 처리 구간을 SELECT ... FOR UPDATE로 잠가 lost update를 방지하며, 셋째 클라이언트가 보내는 멱등키(idempotency key)를 저장해 같은 요청 재시도를 한 번만 반영합니다. 이렇게 하면 동시 요청과 재시도 모두에서 단 한 번만 결제됩니다."},
  {"id":"sc-db-24","cat":"DB","level":"중급","q":"EXPLAIN과 EXPLAIN ANALYZE의 차이는 무엇이고, 계획에서 가장 먼저 봐야 할 신호는 무엇인가요?","a":"EXPLAIN은 옵티마이저의 추정 계획(cost, 추정 rows)만 보여주고, EXPLAIN ANALYZE는 실제로 실행해 actual time과 실제 rows, 반복 횟수까지 보여줍니다. 제일 먼저 보는 신호는 추정 rows와 실제 rows의 괴리입니다. 크게 벌어지면 통계가 낡았거나 분포 추정이 틀린 것이라 나쁜 계획의 원인이 됩니다. BUFFERS로 실제 읽은 페이지도 함께 봅니다."},
  {"id":"sc-db-25","cat":"DB","level":"중급","q":"Nested Loop 조인과 Hash 조인은 각각 어떤 상황에서 유리한가요?","a":"Nested Loop는 한쪽 결과가 적고 다른 쪽에 조인 키 인덱스가 있을 때, 적은 행마다 인덱스로 빠르게 찾아 유리합니다. Hash Join은 양쪽이 대량이고 등호(=) 조인일 때 한쪽으로 해시 테이블을 만들어 한 번에 매칭하므로 유리합니다. 정렬이 이미 돼 있거나 정렬이 싼 대량 데이터에는 Sort-Merge Join이 적합합니다."},
  {"id":"sc-db-26","cat":"DB","level":"심화","q":"N+1 문제가 무엇이고, select_related·prefetch_related·fetch join은 어떻게 다른가요?","a":"목록 N건을 조회한 뒤 각 건의 연관 데이터를 1건씩 또 조회해 쿼리가 1+N번 나가는 게 N+1입니다. Django의 select_related는 FK/1:1을 SQL JOIN으로 한 번에 가져오고, prefetch_related는 M:N/역참조를 별도 쿼리로 가져와 파이썬 메모리에서 조인합니다. JPA의 fetch join/@EntityGraph가 select_related에, batch size 설정이 prefetch 방식에 대응됩니다."},
  {"id":"sc-db-27","cat":"DB","level":"심화","q":"OFFSET 페이지네이션이 뒤로 갈수록 느려지는 이유와 keyset(cursor) 방식의 트레이드오프는 무엇인가요?","a":"OFFSET N은 앞의 N행을 실제로 읽고 버린 뒤 다음을 반환하므로 N이 커질수록 스캔량이 선형으로 늘어 느려집니다. keyset은 마지막으로 본 정렬 키를 WHERE 조건으로 받아 인덱스로 바로 그 지점부터 읽어 깊은 페이지에서도 일정하게 빠릅니다. 대신 임의 페이지 점프가 어렵고 정렬 키가 인덱스로 정렬돼 있어야 하며 동점 처리에 주의해야 합니다. DRF의 CursorPagination이 이 방식입니다."},
  {"id":"sc-db-28","cat":"DB","level":"중급","q":"인덱스가 있는데도 옵티마이저가 Seq Scan을 선택하는 경우는 왜 그런가요?","a":"조회 대상이 테이블의 상당 비율이면 인덱스로 랜덤 I/O를 반복하는 것보다 순차로 한 번에 읽는 Seq Scan이 더 싸다고 옵티마이저가 비용 계산을 합니다. 선택성이 낮은 조건, 작은 테이블, 통계가 낡아 rows 추정이 틀린 경우가 대표적입니다. 통계가 원인이면 ANALYZE로 갱신하면 계획이 바뀝니다."},
  {"id":"sc-db-29","cat":"DB","level":"심화","q":"추정 rows와 실제 rows가 크게 차이 나는 원인은 무엇이고 어떻게 대처하나요?","a":"원인은 ANALYZE가 안 돌아 통계(pg_stats)가 낡았거나, 컬럼 간 상관관계로 단일 컬럼 통계로는 분포를 못 잡거나, 함수로 감싼 조건이라 추정이 안 되는 경우입니다. 대처는 ANALYZE/autovacuum으로 통계를 최신화하고, 다중 컬럼 통계(CREATE STATISTICS)를 만들거나, 표현식 인덱스로 추정 가능하게 바꾸는 것입니다. 괴리가 크면 조인 순서·방식 선택이 틀어집니다."},
  {"id":"sc-db-30","cat":"DB","level":"중급","q":"행의 존재 여부 확인이나 개수 확인에서 count(*)와 exists()는 각각 언제 쓰는 게 맞나요?","a":"단지 '하나라도 있는가'를 볼 때는 exists()를 써야 합니다. 첫 행을 찾는 즉시 멈추기 때문입니다. 반면 count(*)는 조건에 맞는 전체를 세느라 모든 행을 훑어 비용이 큽니다. Django에서도 존재 확인은 .exists(), 개수는 .count()를 쓰고, 컬렉션을 다 가져와 len()으로 세는 건 피해야 합니다."},
  {"id":"sc-db-31","cat":"DB","level":"중급","q":"파티셔닝과 샤딩의 차이는 무엇이고, 샤드 키를 잘못 고르면 어떤 문제가 생기나요?","a":"파티셔닝은 한 서버 안에서 테이블을 range/list/hash로 쪼개 partition pruning으로 스캔 범위를 줄이는 것이고, 샤딩은 데이터를 여러 서버에 나눠 저장해 수평 확장하는 것입니다. 샤드 키를 잘못 고르면 특정 샤드에 트래픽이 몰리는 핫스팟이 생기고, 키 변경 시 데이터 재분배(rebalancing) 비용과 크로스 샤드 조인·분산 트랜잭션의 어려움이 커집니다."},
  {"id":"sc-db-32","cat":"DB","level":"중급","q":"read replica를 두면 생기는 정합성 문제는 무엇이고 어떻게 해결하나요?","a":"비동기 복제에서는 replication lag 때문에 방금 primary에 쓴 데이터가 replica에 아직 없어, 쓰고 바로 읽으면 옛 값을 보는 read-after-write 불일치가 생깁니다. 해결은 직후 중요한 읽기는 primary로 보내거나, 동기 복제를 쓰거나, lag을 모니터링하며 일정 시간 sticky하게 primary를 읽는 식입니다. Django는 DATABASE ROUTERS로 읽기/쓰기 라우팅을 제어합니다."},
  {"id":"sc-db-33","cat":"DB","level":"심화","q":"어떤 시스템을 'CA 시스템'이라고 부르는 게 부정확한 이유와, PostgreSQL 단일 노드는 CAP에서 어떻게 분류해야 하나요?","a":"CAP에서 P(파티션 내성)는 분산 시스템에서 선택 사항이 아니라 네트워크 분할이 일어나면 무조건 직면하는 현실입니다. 그래서 분할이 났을 때 C와 A 중 무엇을 포기할지의 문제이고, 분할을 가정하지 않는 'CA'라는 표현은 의미가 약합니다. 단일 노드 PostgreSQL은 애초에 분할 대상이 없으므로 CAP로 분류하는 것 자체가 부적절하고, 트랜잭션은 그냥 ACID로 강한 일관성을 보장합니다."},
  {"id":"sc-db-34","cat":"DB","level":"중급","q":"NoSQL 대신 PostgreSQL의 jsonb로 충분한 경우는 언제인가요?","a":"스키마가 유동적인 반정형 데이터를 다루되 데이터 규모와 쓰기 부하가 단일 RDB로 감당되고, 같은 트랜잭션 안에서 관계형 데이터와 함께 강한 일관성으로 다뤄야 한다면 jsonb로 NoSQL 요구를 흡수할 수 있습니다. GIN 인덱스로 @> 같은 포함 검색도 인덱싱됩니다. 반대로 초대용량·극단적 쓰기 확장·다중 리전 분산이 핵심이면 전용 NoSQL이 맞습니다."},
  {"id":"sc-db-35","cat":"DB","level":"심화","q":"커넥션 풀 크기를 무작정 늘리면 오히려 나빠지는 이유와 PgBouncer가 필요한 이유는 무엇인가요?","a":"각 연결은 PostgreSQL에서 별도 프로세스라 메모리·컨텍스트 스위칭 비용이 들고, CPU/디스크 자원이 한정돼 있어 연결을 늘려도 동시에 일할 수 있는 수를 넘으면 경합만 늘어 처리량이 떨어지고 응답이 느려집니다. Django의 CONN_MAX_AGE는 프로세스별 재사용일 뿐 전역 풀이 아니라, 워커가 많아지면 연결이 폭증합니다. 그래서 PgBouncer 같은 외부 풀러로 transaction pooling을 해 실제 DB 연결 수를 작게 유지합니다. HikariCP가 PgBouncer 역할에 대응됩니다."},
  {"id":"sc-db-36","cat":"DB","level":"심화","q":"VACUUM을 하지 않으면 PostgreSQL에서 어떤 문제가 생기나요?","a":"MVCC 때문에 UPDATE/DELETE가 dead tuple을 남기는데 VACUUM이 안 돌면 이게 회수되지 않아 테이블·인덱스가 bloat되어 디스크와 스캔 비용이 늘고, visibility map이 갱신되지 않아 Index Only Scan 효율도 떨어집니다. 더 심각하게는 트랜잭션 ID가 한 바퀴 도는 XID wraparound를 막지 못해 최악의 경우 DB가 쓰기를 멈추게 됩니다. 그래서 autovacuum이 돌도록 유지해야 합니다."},
  {"id":"sc-db-37","cat":"DB","level":"심화","q":"캐시를 쓸 때 정합성 문제와 캐시 스탬피드(thundering herd)는 어떻게 막나요?","a":"정합성은 보통 look-aside로 읽고 쓰기 시 캐시를 무효화하거나 write-through로 갱신하는데, 무효화 타이밍·경합 때문에 stale 데이터가 남을 수 있어 TTL과 명시적 무효화를 함께 씁니다. 스탬피드는 인기 키가 동시에 만료되면 많은 요청이 한꺼번에 DB로 몰리는 현상으로, 갱신을 한 요청만 하도록 lock/single-flight를 걸거나, TTL을 분산(jitter)하거나, 만료 직전 미리 갱신하는 식으로 막습니다."},
  {"id":"sc-algo-1","cat":"ALGO","level":"기본","q":"이중 for문 안에서 이분 탐색을 호출하면 전체 시간 복잡도는 어떻게 되나요?","a":"바깥 이중 루프가 O(n^2)이고 그 안에서 매번 이분 탐색 O(log n)을 호출하므로 전체는 O(n^2 log n)입니다. 복잡도는 중첩된 반복 구조를 곱으로 합산하면 되고, 상수나 저차항은 버립니다."},
  {"id":"sc-algo-2","cat":"ALGO","level":"기본","q":"입력 크기 n이 10^5일 때 O(n^2) 알고리즘이 시간 안에 통과할 수 있나요?","a":"통과하기 어렵습니다. n=10^5이면 n^2은 10^10이고, 보통 '1초에 약 1억(10^8) 연산'을 기준으로 잡으면 약 100초가 걸려 시간 초과입니다. n=10^5에서는 O(n log n) 이하로 풀어야 하고, O(n^2)은 n이 5000 정도까지만 허용됩니다."},
  {"id":"sc-algo-3","cat":"ALGO","level":"중급","q":"동적 배열의 append가 상각(amortized) O(1)인 이유를 설명해 주세요.","a":"배열이 가득 차면 더 큰 배열(보통 2배)을 새로 할당하고 기존 원소를 복사하는데, 이 복사 비용은 O(n)이지만 자주 일어나지 않습니다. 2배씩 키우면 n번 append할 때 총 복사 비용이 O(n)으로 분산되어, 한 번당 평균 비용이 O(1)이 됩니다. 이것이 상각 분석입니다."},
  {"id":"sc-algo-4","cat":"ALGO","level":"기본","q":"Python list를 큐처럼 쓰면 느린 이유와 올바른 대안은 무엇인가요?","a":"list는 동적 배열이라 list.pop(0)이나 맨 앞 삽입은 뒤 원소를 전부 한 칸씩 당겨야 해서 O(n)입니다. 큐가 필요하면 collections.deque를 써야 하며, deque는 양끝 삽입·삭제가 O(1)입니다."},
  {"id":"sc-algo-5","cat":"ALGO","level":"중급","q":"해시 테이블이 평균 O(1)인데 최악 O(n)인 이유와 완화책은 무엇인가요?","a":"해시 충돌이 거의 없으면 조회·삽입이 평균 O(1)이지만, 모든 키가 한 버킷으로 충돌하면(체이닝 기준) 최악 O(n)이 됩니다. 완화책은 load factor를 일정 이하로 유지하며 리해싱(버킷 확장)하고, 좋은 해시 함수를 쓰는 것입니다. Python dict/set이 이를 내부적으로 처리합니다."},
  {"id":"sc-algo-6","cat":"ALGO","level":"중급","q":"퀵 정렬과 머지 정렬을 안정성·메모리·최악 복잡도 관점에서 비교해 주세요.","a":"퀵 정렬은 in-place라 추가 메모리가 거의 없고 평균 O(n log n)이지만 불안정하며 피벗이 나쁘면 최악 O(n^2)입니다. 머지 정렬은 항상 O(n log n)으로 안정 정렬이지만 O(n) 추가 메모리가 필요합니다. Python의 sort는 머지 기반 Timsort로 안정 정렬입니다."},
  {"id":"sc-algo-7","cat":"ALGO","level":"심화","q":"파라메트릭 서치와 일반 이분 탐색의 차이는 무엇인가요?","a":"일반 이분 탐색은 정렬된 배열에서 특정 값을 찾지만, 파라메트릭 서치는 '최적화 문제'를 'X가 가능한가?'라는 yes/no 결정 문제로 바꿔서 답 자체를 이분 탐색하는 기법입니다. 핵심은 답이 단조성을 가져 결정함수가 어떤 경계 이후 항상 참(또는 거짓)이 되도록 만드는 것입니다. 랜선 자르기, 최소 거리의 최대화 같은 문제가 대표적입니다."},
  {"id":"sc-algo-8","cat":"ALGO","level":"중급","q":"구간 합 질의가 Q번 들어올 때 전체를 O(N+Q)로 처리하려면 어떻게 하나요?","a":"누적합(prefix sum) 배열을 O(N)으로 한 번 전처리해두면, 구간 [i, j] 합을 prefix[j] - prefix[i-1]로 O(1)에 답할 수 있습니다. 따라서 Q번의 질의가 O(Q)가 되어 전체 O(N+Q)입니다. 2차원이면 2D 누적합으로 확장합니다."},
  {"id":"sc-algo-9","cat":"ALGO","level":"심화","q":"유니온-파인드에서 경로 압축과 union by rank는 각각 무엇을 최적화하나요?","a":"경로 압축은 find 과정에서 거친 노드들을 루트에 직접 연결해 트리 높이를 낮춰 이후 find를 빠르게 합니다. union by rank(또는 size)는 합칠 때 낮은 트리를 높은 트리 아래에 붙여 트리가 깊어지는 것을 막습니다. 둘을 함께 쓰면 연산당 거의 상수에 가까운 O(α(n))이 됩니다."},
  {"id":"sc-algo-10","cat":"ALGO","level":"심화","q":"Python에는 내장 균형 트리가 없는데, '정렬 상태 유지 + 이분 삽입'은 어떻게 구현하나요?","a":"정렬된 list에 bisect.insort(또는 bisect_left로 위치를 찾아 insert)를 쓰면 정렬을 유지하며 삽입할 수 있는데, list 삽입 자체가 O(n)이라 빈번하면 비효율적입니다. 더 나은 방법은 sortedcontainers의 SortedList를 쓰는 것으로, 삽입·삭제·검색이 O(log n)에 가깝습니다. Java라면 TreeMap(레드블랙 트리)에 해당합니다."},
  {"id":"sc-algo-11","cat":"ALGO","level":"기본","q":"BFS와 DFS는 각각 어떤 상황에 적합한가요?","a":"BFS는 가중치가 없는 그래프의 최단 경로나 레벨 단위 탐색에 적합하며 deque(큐)로 구현합니다. DFS는 경로 탐색, 연결 요소 세기, 사이클 판별, 위상 정렬 등에 적합하며 재귀나 스택으로 구현하는데, 재귀 깊이 한계에 주의해야 합니다."},
  {"id":"sc-algo-12","cat":"ALGO","level":"중급","q":"다익스트라가 음수 간선에서 틀리는 이유와 대안은 무엇인가요?","a":"다익스트라는 한 번 확정한 노드의 최단 거리는 다시 줄지 않는다는 그리디 가정을 쓰는데, 음수 간선이 있으면 나중에 더 짧은 경로가 생길 수 있어 그 가정이 깨집니다. 대안으로는 음수 간선을 처리하고 음수 사이클까지 판별하는 벨만-포드, 모든 쌍 최단경로면 플로이드-워셜을 씁니다."},
  {"id":"sc-algo-13","cat":"ALGO","level":"심화","q":"플로이드-워셜에서 경유지 k 루프가 가장 바깥에 와야 하는 이유는 무엇인가요?","a":"k는 '0~k번 노드만 경유지로 허용했을 때의 최단거리'라는 DP 단계를 의미합니다. k를 가장 바깥에 두어야 각 단계에서 dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])를 계산할 때 dist[i][k], dist[k][j]가 이미 k-1까지 반영된 올바른 값이 됩니다. i나 j를 바깥에 두면 점화식이 깨져 틀린 답이 나옵니다."},
  {"id":"sc-algo-14","cat":"ALGO","level":"중급","q":"위상 정렬이 불가능한 경우(사이클)는 어떻게 감지하나요?","a":"Kahn 알고리즘에서는 진입 차수가 0인 노드부터 제거해 나가는데, 정렬 결과에 포함된 노드 수가 전체 노드 수보다 적으면 사이클이 남아 있다는 뜻입니다. DFS 기반이면 방문 중(회색) 상태인 노드로 다시 가는 역방향 간선이 발견되면 사이클로 판정합니다."},
  {"id":"sc-algo-15","cat":"ALGO","level":"중급","q":"밀집 그래프에서 MST를 구할 때 크루스칼과 프림 중 무엇을 선택하나요?","a":"밀집 그래프(간선이 많은 경우)에는 프림이 유리합니다. 크루스칼은 간선을 모두 정렬하므로 O(E log E)로 간선 수에 좌우되어 희소 그래프에 유리하고, 프림은 인접 행렬·배열 기반이면 O(V^2)라 정점 대비 간선이 많은 밀집 그래프에 적합합니다."},
  {"id":"sc-algo-16","cat":"ALGO","level":"심화","q":"0-1 BFS가 가중치가 0과 1뿐인 그래프에서 다익스트라보다 빠른 이유는 무엇인가요?","a":"간선 가중치가 0 또는 1뿐이면 우선순위 큐 대신 deque를 써서, 가중치 0 간선은 앞(appendleft)에, 1 간선은 뒤(append)에 넣어 거리 순서를 자연스럽게 유지할 수 있습니다. 힙의 O(log n) 연산 없이 O(V+E)에 동작하므로 다익스트라보다 빠릅니다."},
  {"id":"sc-algo-17","cat":"ALGO","level":"중급","q":"어떤 문제를 보고 'DP다'라고 판단하는 신호 두 가지와 상태 정의 방법은 무엇인가요?","a":"DP의 두 신호는 '최적 부분 구조'(부분 문제의 최적해로 전체 최적해를 구성)와 '중복되는 부분 문제'(같은 하위 계산이 반복)입니다. 이때 그 부분 문제를 유일하게 식별하는 변수들을 상태로 잡고(예: dp[i] = i까지의 최적값), 상태 간 관계를 점화식으로 정의한 뒤 Top-down(@lru_cache)이나 Bottom-up으로 채웁니다."},
  {"id":"sc-algo-18","cat":"ALGO","level":"심화","q":"그리디가 최적해를 보장하는지 어떻게 판단하고, 보장 못 할 때의 반례는 어떻게 다루나요?","a":"그리디는 '탐욕적 선택 속성'과 '최적 부분 구조'가 성립할 때만 최적을 보장하므로, 매 단계 국소 최적이 전역 최적으로 이어진다는 정당성을 증명(교환 논법 등)해야 합니다. 보장이 의심되면 작은 반례를 만들어 검증하고, 반례가 나오면 그리디 대신 DP로 전환합니다."},
  {"id":"sc-algo-19","cat":"ALGO","level":"심화","q":"값이 자주 갱신되면서 구간 합 질의도 잦은 문제에는 어떤 자료구조를 쓰고 복잡도는 어떻게 되나요?","a":"원소 값이 자주 바뀌면 누적합은 갱신마다 O(n)이라 비효율적이므로 세그먼트 트리나 펜윅 트리(BIT)를 씁니다. 둘 다 점 갱신과 구간 질의를 각각 O(log n)에 처리합니다. 구현이 간단하고 구간 합 위주면 펜윅, 더 일반적인 질의(최솟값 등)나 구간 갱신이 필요하면 세그먼트 트리를 선택합니다."},
  {"id":"sc-algo-20","cat":"ALGO","level":"심화","q":"비트마스킹 DP에서 n의 한계와 상태 표현 방식을 설명해 주세요.","a":"원소 집합의 부분집합을 정수 비트로 표현하는데, 상태가 2^n개라 메모리·시간상 n은 보통 20~25 정도가 한계입니다. 대표 예가 외판원(TSP)으로 dp[mask][i] = 방문 집합이 mask이고 현재 i에 있을 때의 최소 비용처럼 정의하며, mask의 각 비트가 해당 노드 방문 여부를 나타냅니다."},
  {"id":"sc-algo-21","cat":"ALGO","level":"심화","q":"KMP가 빠른 이유와 실패 함수의 역할은 무엇인가요?","a":"단순 문자열 매칭은 불일치 시 패턴을 한 칸만 밀어 O(nm)이지만, KMP는 실패 함수(접두사이자 접미사인 가장 긴 길이)를 미리 계산해 불일치 시 이미 일치한 부분을 활용해 패턴을 여러 칸 건너뜁니다. 덕분에 텍스트 포인터를 되돌리지 않아 전체 O(n+m)에 동작합니다."},
  {"id":"sc-algo-22","cat":"ALGO","level":"심화","q":"시간 초과가 났을 때 어떤 순서로 최적화를 시도하나요?","a":"먼저 입력 한계로 목표 복잡도를 역산해 알고리즘 자체가 과한지 확인하고, 맞다면 더 낮은 복잡도(예: O(n^2)→O(n log n))로 재설계합니다. 알고리즘이 적정하면 입출력 가속(sys.stdin.readline), 불필요한 연산·중복 계산 제거(메모이제이션), 적절한 자료구조 교체, 상수 줄이기 순으로 시도합니다."},
  {"id":"sc-algo-23","cat":"ALGO","level":"심화","q":"재귀 깊이가 깊어 DFS가 문제가 될 때 Python에서 대처하는 방법 두 가지는 무엇인가요?","a":"첫째, sys.setrecursionlimit으로 재귀 한도를 늘리는 방법이 있는데, 너무 깊으면 스택 오버플로 위험이 있습니다. 둘째, 재귀를 명시적 스택을 쓰는 반복(iterative) DFS로 변환해 호출 스택 한계를 우회하는 방법이 더 안전합니다."},
  {"id":"sc-cs-1","cat":"CS","level":"기본","q":"브라우저 주소창에 URL을 입력하고 엔터를 치면 화면에 페이지가 그려지기까지 어떤 순서로 일이 일어나나요?","a":"먼저 DNS로 도메인을 IP로 변환하고, 그 IP로 TCP 3-way handshake를 맺습니다. HTTPS면 이어서 TLS 핸드셰이크로 암호화 채널을 만들고, 그 위에서 HTTP 요청을 보냅니다. 서버가 요청을 처리해 응답을 돌려주면 브라우저가 HTML/CSS/JS를 파싱해 렌더링합니다. 즉 DNS→TCP→(TLS)→HTTP 요청→서버 처리→응답→렌더 순서입니다."},
  {"id":"sc-cs-2","cat":"CS","level":"기본","q":"401, 403, 500, 502, 503 상태코드는 각각 어떤 상황에서 쓰며 서로 어떻게 다른가요?","a":"401은 인증이 안 된 상태(누구인지 모름), 403은 인증은 됐지만 권한이 없는 상태(누구인지는 알지만 허용 안 됨)입니다. 500은 서버 애플리케이션 내부에서 처리 중 터진 에러이고, 502는 리버스 프록시/게이트웨이가 뒤쪽 서버로부터 잘못된 응답을 받은 경우, 503은 서버가 과부하나 점검 등으로 일시적으로 요청을 처리할 수 없는 상태입니다. 502/503은 보통 프록시 앞단 또는 가용성 문제, 500은 애플리케이션 버그 신호입니다."},
  {"id":"sc-cs-3","cat":"CS","level":"중급","q":"PUT과 POST의 멱등성 차이는 무엇이고, 재시도 관점에서 왜 중요한가요?","a":"PUT은 멱등이라 같은 요청을 여러 번 보내도 결과 상태가 동일하지만, POST는 비멱등이라 반복하면 리소스가 중복 생성될 수 있습니다. 그래서 네트워크 타임아웃 등으로 클라이언트가 안전하게 재시도하려면 PUT은 그대로 재전송해도 되지만, POST는 중복 생성을 막기 위해 멱등키(idempotency key) 같은 장치가 필요합니다."},
  {"id":"sc-cs-4","cat":"CS","level":"중급","q":"HTTP가 stateless라는 게 무슨 의미이고, 그런데도 로그인 상태는 어떻게 유지되나요?","a":"stateless는 각 HTTP 요청이 독립적이라 서버가 이전 요청을 기억하지 않는다는 뜻입니다. 그래서 로그인 상태는 요청마다 쿠키의 세션 ID나 Authorization 헤더의 JWT 같은 자격 증명을 함께 실어 보내서 서버가 매 요청마다 누구인지 식별하는 방식으로 유지합니다. 상태 자체는 클라이언트가 들고 다니거나 서버 세션 저장소에 두고 식별자만 주고받습니다."},
  {"id":"sc-cs-5","cat":"CS","level":"중급","q":"TCP 연결을 맺을 때 왜 2단계가 아니라 3-way handshake가 필요한가요?","a":"양쪽 모두 서로의 송신/수신 능력과 시퀀스 번호를 확인해야 하기 때문입니다. 2단계만으로는 서버가 보낸 SYN-ACK에 대한 클라이언트의 확인이 없어, 지연된 옛 연결 요청이 재활용되는 등 양방향 합의가 불완전합니다. 3단계(SYN → SYN,ACK → ACK)를 거쳐야 양쪽의 초기 시퀀스 번호가 서로 확인되어 신뢰성 있는 양방향 통신을 시작할 수 있습니다."},
  {"id":"sc-cs-6","cat":"CS","level":"중급","q":"TCP의 흐름 제어와 혼잡 제어는 각각 무엇을 보호하기 위한 것이고 어떻게 다른가요?","a":"흐름 제어는 수신자를 보호하는 것으로, 수신 버퍼가 넘치지 않도록 수신자가 알려준 윈도우 크기(슬라이딩 윈도우)만큼만 보냅니다. 혼잡 제어는 네트워크 전체를 보호하는 것으로, slow start처럼 전송량을 점진적으로 늘리며 패킷 손실을 혼잡 신호로 보고 전송 속도를 조절합니다. 즉 흐름 제어는 종단 간(수신자) 보호, 혼잡 제어는 중간 네트워크 보호가 목적입니다."},
  {"id":"sc-cs-7","cat":"CS","level":"심화","q":"TIME_WAIT 상태는 왜 존재하며, 이게 많이 쌓이면 어떤 문제가 생기나요?","a":"연결을 먼저 닫은(active close) 쪽이 마지막 ACK 유실에 대비하고, 지연 도착한 옛 패킷이 새 연결에 섞이지 않도록 일정 시간(보통 2*MSL) 대기하는 상태입니다. 그런데 짧은 연결을 대량으로 맺는 서버에서는 TIME_WAIT 소켓이 누적되어 로컬 포트와 소켓 자원이 고갈되고 새 연결 생성이 막힐 수 있습니다. keep-alive로 연결 재사용을 늘리거나 커널 파라미터 튜닝으로 완화합니다."},
  {"id":"sc-cs-8","cat":"CS","level":"중급","q":"DNS는 보통 UDP를 쓰는데 그 이유는 무엇이고, 언제 TCP로 전환되나요?","a":"DNS 질의는 대부분 작은 단일 패킷이라 연결 설정 오버헤드가 없는 UDP가 빠르고 효율적이기 때문입니다. 응답이 손실되면 그냥 재질의하면 됩니다. 다만 응답 크기가 UDP 한계(전통적으로 512바이트)를 넘거나 영역 전송(zone transfer)처럼 큰 데이터를 주고받을 때는 신뢰성이 필요해 TCP로 전환합니다."},
  {"id":"sc-cs-9","cat":"CS","level":"심화","q":"TCP는 어떤 메커니즘들로 데이터 전송의 신뢰성을 보장하나요?","a":"각 바이트에 시퀀스 번호를 붙여 순서를 보장하고, 수신자가 ACK로 수신을 확인합니다. ACK가 오지 않으면 타임아웃이나 중복 ACK를 근거로 재전송하고, 체크섬으로 손상을 검출합니다. 여기에 흐름 제어와 혼잡 제어로 손실을 줄여, 순서 보장·손실 복구·중복 제거를 통해 신뢰성 있는 바이트 스트림을 제공합니다."},
  {"id":"sc-cs-10","cat":"CS","level":"심화","q":"HTTPS는 어떻게 도청과 변조를 동시에 막고, 통신에 쓸 세션키는 어떻게 합의하나요?","a":"TLS 핸드셰이크에서 인증서로 서버 신원을 검증하고, ECDHE 같은 키 교환으로 양쪽이 같은 대칭 세션키를 안전하게 합의합니다. 이후 통신은 이 대칭키로 암호화해 도청을 막고, 메시지 인증 코드(MAC/AEAD)로 무결성을 검증해 변조를 탐지합니다. 즉 암호화로 도청을, 무결성 검증으로 변조를 막고, 비대칭 키 교환으로 세션키를 합의합니다."},
  {"id":"sc-cs-11","cat":"CS","level":"중급","q":"세션 기반 인증과 JWT의 트레이드오프는 무엇이고, 로그아웃은 각각 어떻게 처리하나요?","a":"세션은 서버가 상태를 저장하므로 즉시 무효화(로그아웃)가 쉽지만 서버 저장소와 확장 시 공유가 필요합니다. JWT는 서버가 상태를 안 가지는 stateless라 확장에 유리하지만, 발급된 토큰을 만료 전에 강제 무효화하기 어렵습니다. 그래서 JWT는 access를 짧게 두고 refresh로 갱신하며, 로그아웃은 refresh 폐기나 블랙리스트 같은 별도 장치로 처리합니다."},
  {"id":"sc-cs-12","cat":"CS","level":"중급","q":"CORS는 누가 강제하는 정책이며, 프리플라이트 요청은 어떤 조건에서 발생하나요?","a":"CORS는 브라우저가 강제하는 정책이라 서버 대 서버 통신에는 적용되지 않습니다. SOP(동일 출처 정책) 때문에 다른 출처로의 요청을 제한하고, 단순 요청이 아닌 경우(PUT/DELETE 등 메서드, 커스텀 헤더, JSON 같은 특정 Content-Type)에는 실제 요청 전에 OPTIONS 프리플라이트로 허용 여부를 먼저 확인합니다. 서버는 Access-Control-Allow-* 헤더로 허용 범위를 응답합니다."},
  {"id":"sc-cs-13","cat":"CS","level":"중급","q":"쿠키의 HttpOnly와 SameSite 속성은 각각 어떤 공격을 막아주나요?","a":"HttpOnly는 JavaScript에서 쿠키 접근을 막아, XSS로 스크립트가 주입되어도 세션 쿠키 탈취를 어렵게 합니다. SameSite는 다른 출처에서 시작된 요청에 쿠키가 자동으로 실리는 것을 제한해 CSRF를 완화합니다. 함께 Secure 속성으로 HTTPS 전송을 강제하면 더 안전합니다."},
  {"id":"sc-cs-14","cat":"CS","level":"기본","q":"도메인 이름을 IP로 바꾸는 DNS 질의는 캐시를 포함해 어떤 순서로 진행되나요?","a":"먼저 브라우저/OS의 로컬 캐시와 hosts를 확인하고, 없으면 리졸버(보통 ISP나 공용 DNS)에게 묻습니다. 리졸버 캐시에도 없으면 루트 네임서버 → TLD 서버(.com 등) → 권한 있는 네임서버 순으로 반복 질의해 최종 IP를 받아옵니다. 각 응답은 TTL 동안 캐시되어 다음 질의를 빠르게 합니다. 레코드는 A/AAAA(IP), CNAME(별칭), MX(메일) 등이 있습니다."},
  {"id":"sc-cs-15","cat":"CS","level":"심화","q":"HTTP/1.1, HTTP/2, HTTP/3에서 HOL 블로킹은 각각 어디서 발생하고 어떻게 해결되나요?","a":"HTTP/1.1은 한 연결에서 응답을 순서대로 받아야 해서 애플리케이션 계층에서 HOL 블로킹이 생기고, keep-alive와 다중 연결로 일부만 완화됩니다. HTTP/2는 멀티플렉싱으로 애플리케이션 계층 HOL은 해결했지만 TCP 위에 있어 패킷 손실 시 TCP 계층 HOL이 남습니다. HTTP/3는 UDP 기반 QUIC를 써서 스트림을 독립시켜 TCP HOL까지 제거합니다."},
  {"id":"sc-cs-16","cat":"CS","level":"심화","q":"HTTP/3는 UDP 위에서 동작하는데 어떻게 신뢰성을 보장하나요?","a":"HTTP/3의 전송 프로토콜인 QUIC가 UDP 위에서 시퀀스/ACK·재전송·흐름 제어·혼잡 제어를 자체적으로 구현해 신뢰성을 제공합니다. 또 스트림을 독립적으로 관리해 한 스트림의 손실이 다른 스트림을 막지 않게 하고, TLS 1.3을 통합해 연결 설정을 줄이며 0-RTT 재연결도 지원합니다. 즉 신뢰성 기능을 TCP가 아니라 QUIC가 UDP 위에서 직접 담당합니다."},
  {"id":"sc-cs-17","cat":"CS","level":"중급","q":"L4 로드밸런서와 L7 로드밸런서는 무엇을 기준으로 트래픽을 분배하며, 쿠키 기반 라우팅은 어느 쪽인가요?","a":"L4는 전송 계층 정보인 IP와 포트만 보고 분배하므로 빠르지만 내용은 모릅니다. L7은 애플리케이션 계층까지 보고 URL, 헤더, 쿠키 등으로 라우팅하거나 콘텐츠 기반 분기, TLS 종료 등을 할 수 있습니다. 따라서 특정 쿠키로 같은 서버에 고정시키는 sticky session 같은 쿠키 기반 라우팅은 L7에서 가능합니다."},
  {"id":"sc-cs-18","cat":"CS","level":"기본","q":"HTTP, TLS, TCP, IP는 OSI/TCP-IP 모델에서 각각 어느 계층에 속하나요?","a":"HTTP는 응용 계층, TLS는 응용과 전송 사이(보통 표현/세션 또는 응용 계층으로 분류)에서 동작하는 보안 계층, TCP는 전송 계층, IP는 인터넷(네트워크) 계층입니다. OSI 7계층과 TCP/IP 4계층은 실제 구현이라기보다 프로토콜을 역할별로 분류하는 틀로 이해하면 됩니다."},
  {"id":"sc-cs-19","cat":"CS","level":"중급","q":"애플리케이션 서버 앞에 Nginx 같은 리버스 프록시를 두는 이유를 세 가지 이상 설명해 주세요.","a":"첫째, TLS 종료를 프록시에서 처리해 WAS 부담을 줄입니다. 둘째, 정적 파일을 직접 서빙하고 캐싱해 효율을 높입니다. 셋째, 여러 WAS로 로드밸런싱하고 헬스체크로 가용성을 관리합니다. 그 외에도 보안 경계(내부 서버 은닉), 압축, 요청 버퍼링, 속도 제한 같은 횡단 관심사를 한곳에서 처리할 수 있습니다. 예: Django 앞에 Nginx + Gunicorn 구성."},
  {"id":"sc-cs-20","cat":"CS","level":"기본","q":"프로세스와 스레드의 차이를 메모리 관점에서 설명해 주세요.","a":"프로세스는 각자 독립된 가상 메모리 공간(코드/데이터/힙/스택)을 가져 서로 격리되지만, 스레드는 같은 프로세스 안에서 코드·데이터·힙을 공유하고 스택만 별도로 가집니다. 그래서 스레드 간 통신은 공유 메모리로 빠르지만 동기화가 필요하고, 프로세스 간은 격리되어 안전하지만 IPC가 필요하며 컨텍스트 스위칭 비용도 더 큽니다."},
  {"id":"sc-cs-21","cat":"CS","level":"심화","q":"컨텍스트 스위칭의 직접 비용과 간접 비용은 각각 무엇인가요?","a":"직접 비용은 레지스터·프로그램 카운터·스택 포인터 등 CPU 상태를 저장하고 복원하며 스케줄러가 도는 비용입니다. 간접 비용은 전환 후 캐시와 TLB가 무효화되어 워킹셋을 다시 채우는 동안 캐시 미스가 늘어 성능이 떨어지는 부분입니다. 보통 이 간접 비용(캐시/TLB 효과)이 직접 비용보다 크게 작용할 수 있습니다."},
  {"id":"sc-cs-22","cat":"CS","level":"중급","q":"라운드로빈 스케줄링에서 타임 퀀텀이 너무 크거나 너무 작으면 각각 어떤 문제가 생기나요?","a":"타임 퀀텀이 너무 크면 FCFS에 가까워져 짧은 작업의 응답성이 나빠지고 대화형 작업이 오래 기다립니다. 반대로 너무 작으면 컨텍스트 스위칭이 빈번해져 오버헤드가 커지고 실제 일하는 시간 비율이 떨어집니다. 따라서 응답성과 오버헤드가 균형을 이루는 적절한 크기로 잡아야 합니다."},
  {"id":"sc-cs-23","cat":"CS","level":"중급","q":"요청당 스레드 하나를 할당하는 서버 모델의 한계는 무엇인가요?","a":"동시 연결이 많아지면 스레드 수가 폭증해 메모리(스레드별 스택)와 컨텍스트 스위칭 비용이 커지고, 블로킹 I/O 동안 스레드가 점유되어 스레드풀이 고갈되면 추가 요청이 대기합니다. 이게 C10K 문제로 이어지며, 그래서 I/O 바운드 고동시성에는 이벤트 루프 기반 비동기(epoll, asyncio) 모델이 유리합니다."},
  {"id":"sc-cs-24","cat":"CS","level":"기본","q":"운영체제가 유저 모드와 커널 모드를 분리하는 이유는 무엇인가요?","a":"하드웨어와 핵심 자원을 보호하기 위해서입니다. 유저 모드 프로그램은 직접 하드웨어나 다른 프로세스 메모리에 접근하지 못하게 막고, 특권 작업(I/O, 메모리 매핑 등)은 시스템 콜을 통해 커널 모드로 전환해서만 수행하게 합니다. 이렇게 권한을 분리해 한 프로그램의 오류나 악성 코드가 시스템 전체를 망가뜨리지 못하게 격리하고 안정성을 확보합니다."},
  {"id":"sc-cs-25","cat":"CS","level":"심화","q":"race condition은 왜 발생하며, counter++ 같은 연산이 왜 위험하고 어떻게 막나요?","a":"여러 스레드가 공유 자원을 동시에 접근하고 적어도 하나가 쓰기를 할 때, 실행 순서에 따라 결과가 달라지는 게 race condition입니다. counter++은 사실 읽기-수정-쓰기 세 단계라 중간에 다른 스레드가 끼어들면 갱신이 유실됩니다. 임계구역을 뮤텍스/락으로 보호하거나, CAS 같은 원자적 연산(AtomicInteger)을 써서 막습니다."},
  {"id":"sc-cs-26","cat":"CS","level":"중급","q":"뮤텍스와 세마포어의 차이를 소유권 관점에서 설명해 주세요.","a":"뮤텍스는 소유권 개념이 있어 락을 건 스레드만 풀 수 있고, 보통 하나의 자원에 대한 상호 배제(동시 1개)에 씁니다. 세마포어는 소유권이 없고 카운트(N)를 가져 동시에 N개까지 접근을 허용하며, 다른 스레드가 해제할 수도 있어 자원 풀 제한이나 신호(signaling)에 적합합니다. 즉 뮤텍스는 잠금/소유, 세마포어는 카운팅/신호용입니다."},
  {"id":"sc-cs-27","cat":"CS","level":"심화","q":"Python에 GIL이 있는데도 멀티스레딩이 의미 있는 경우는 언제인가요?","a":"GIL은 CPython에서 한 번에 한 스레드만 바이트코드를 실행하게 하지만, I/O 대기 중에는 GIL을 놓습니다. 따라서 네트워크/디스크 같은 I/O 바운드 작업은 한 스레드가 대기하는 동안 다른 스레드가 진행되어 멀티스레딩이 효과적입니다. 반면 CPU 바운드는 GIL 때문에 병렬화가 안 되므로 multiprocessing이나 네이티브 확장을 써야 합니다."},
  {"id":"sc-cs-28","cat":"CS","level":"기본","q":"동시성과 병렬성은 어떻게 다르며, 단일 코어에서도 동시성이 가능한가요?","a":"동시성은 여러 작업을 번갈아 처리해 논리적으로 동시에 진행되는 것처럼 보이게 하는 것이고, 병렬성은 여러 코어에서 물리적으로 동시에 실행하는 것입니다. 단일 코어에서도 시분할(컨텍스트 스위칭)로 작업을 번갈아 처리하므로 동시성은 가능하지만, 진짜 병렬 실행은 코어가 여러 개여야 가능합니다."},
  {"id":"sc-cs-29","cat":"CS","level":"중급","q":"Python에서 CPU 바운드 작업을 진짜 병렬로 처리하려면 어떻게 해야 하나요?","a":"GIL 때문에 스레드로는 CPU 바운드를 병렬화할 수 없으므로 multiprocessing을 써서 여러 프로세스로 분산해야 합니다. 각 프로세스는 독립된 인터프리터와 GIL을 가져 여러 코어를 실제로 활용합니다. 그 외 NumPy처럼 GIL을 푸는 네이티브 확장, C 확장, 또는 별도 프로세스/워커 모델을 활용하는 방법도 있습니다."},
  {"id":"sc-cs-30","cat":"CS","level":"심화","q":"데드락이 성립하는 네 가지 조건은 무엇이고, 현실적으로 어떻게 예방하나요?","a":"상호 배제, 점유와 대기, 비선점, 순환 대기 네 조건이 모두 성립할 때 데드락이 생깁니다. 이 중 하나만 깨면 예방되는데, 현실적으로 가장 흔한 방법은 자원에 전역 순서를 정해 항상 같은 순서로 락을 획득해 순환 대기를 없애는 것입니다. 그 외 타임아웃, 한 번에 모든 자원 획득(점유와 대기 제거), 데드락 탐지 후 회복(victim 롤백)도 씁니다."},
  {"id":"sc-cs-31","cat":"CS","level":"심화","q":"DB에서 데드락은 왜 발생하며, 락 순서로 어떻게 줄일 수 있나요?","a":"두 트랜잭션이 서로 다른 순서로 같은 행들에 락을 걸고 상대가 가진 락을 기다리면 순환 대기가 생겨 데드락이 됩니다. DB는 보통 이를 탐지해 한쪽을 victim으로 롤백시킵니다. 애플리케이션에서 항상 동일한 순서(예: id 오름차순)로 행을 갱신·락하도록 통일하면 순환 대기 조건이 깨져 데드락 발생을 크게 줄일 수 있습니다."},
  {"id":"sc-cs-32","cat":"CS","level":"중급","q":"가상 메모리와 페이징은 무엇이며, 페이지 폴트는 어떻게 처리되나요?","a":"가상 메모리는 각 프로세스에 독립적인 연속 주소 공간을 제공해 격리하고 물리 메모리보다 많은 메모리를 과할당할 수 있게 합니다. 페이징은 메모리를 고정 크기 페이지로 나눠 페이지 테이블과 MMU로 가상→물리 주소를 변환합니다. 접근한 페이지가 물리 메모리에 없으면 page fault가 발생하고, OS가 디스크에서 해당 페이지를 적재(디맨드 페이징)한 뒤 매핑을 갱신하고 다시 실행합니다."},
  {"id":"sc-cs-33","cat":"CS","level":"심화","q":"TLB는 무엇이며 컨텍스트 스위칭과 어떤 관계가 있나요?","a":"TLB는 가상→물리 주소 변환 결과를 캐싱해 페이지 테이블을 매번 거치지 않게 해주는 작은 캐시입니다. 컨텍스트 스위칭으로 다른 프로세스의 주소 공간으로 바뀌면 기존 변환이 무효가 되어 TLB가 비워지고(ASID가 없으면 flush), 이후 변환 미스가 늘어 성능이 떨어집니다. 이게 컨텍스트 스위칭의 간접 비용 중 하나입니다."},
  {"id":"sc-cs-34","cat":"CS","level":"심화","q":"페이지 교체에서 LRU와 Clock의 차이는 무엇이고, 실무에서 Clock류를 쓰는 이유는 무엇인가요?","a":"LRU는 가장 오래 참조되지 않은 페이지를 교체해 효율은 좋지만, 매 접근마다 순서를 갱신해야 해 정확한 구현 비용이 큽니다. Clock(2nd chance)은 참조 비트와 원형 포인터로 LRU를 근사해 훨씬 가볍습니다. 그래서 실무 OS는 정확한 LRU 대신 오버헤드가 작으면서 비슷한 효과를 내는 Clock류 근사 알고리즘을 사용합니다."},
  {"id":"sc-cs-35","cat":"CS","level":"심화","q":"WSGI와 ASGI는 어떻게 다르며, 어떤 워크로드에서 ASGI가 유리한가요?","a":"WSGI는 동기 인터페이스라 요청 하나를 워커가 블로킹으로 처리하고(Gunicorn sync worker), ASGI는 비동기를 지원해 이벤트 루프로 한 워커가 다수의 I/O 대기를 동시에 다룹니다. 따라서 외부 API 호출, 웹소켓, 롱폴링처럼 I/O 대기가 많고 동시 연결이 많은 워크로드에서 ASGI(예: Uvicorn)가 유리합니다. CPU 바운드 위주면 WSGI + 프로세스 워커로도 충분합니다. Spring으로 치면 MVC↔WebFlux 관계입니다."},
  {"id":"sc-cs-36","cat":"CS","level":"심화","q":"GIL 환경에서 I/O 바운드와 CPU 바운드 부하는 각각 어떻게 확장해야 하나요?","a":"I/O 바운드는 대기 중 GIL이 풀리므로 스레드나 asyncio(이벤트 루프)로 동시성을 높여 확장합니다. CPU 바운드는 GIL 때문에 스레드로는 병렬화가 안 되므로 multiprocessing이나 여러 프로세스 워커(예: Gunicorn 워커를 코어 수에 맞춰)로 확장하거나 네이티브 확장을 활용합니다. 즉 I/O는 스레드/비동기, CPU는 프로세스 분리가 원칙입니다."},
  {"id":"sc-cs-37","cat":"CS","level":"중급","q":"JSON 대신 Protobuf 같은 바이너리 직렬화를 쓰면 얻는 것과 잃는 것은 무엇인가요?","a":"Protobuf는 바이너리라 페이로드가 작고 인코딩/디코딩이 빠르며 스키마(.proto)로 타입 안전성과 버전 호환을 보장합니다. 대신 사람이 읽기 어렵고 스키마 정의·코드 생성 과정이 필요하며 디버깅이 번거롭습니다. 그래서 서비스 간 고성능 통신에는 Protobuf가, 사람이 보고 다루기 좋은 공개 API에는 JSON이 흔히 적합합니다."},
  {"id":"sc-cs-38","cat":"CS","level":"중급","q":"캐시의 지역성이란 무엇이고, 배열이 연결리스트보다 캐시 친화적인 이유는 무엇인가요?","a":"지역성은 최근 접근한 데이터를 다시 접근하기 쉽고(시간 지역성), 그 근처 데이터를 접근하기 쉽다(공간 지역성)는 성질입니다. 배열은 원소가 메모리에 연속 배치되어 한 캐시 라인을 읽으면 인접 원소들이 함께 올라와 공간 지역성을 잘 활용합니다. 반면 연결리스트는 노드가 메모리에 흩어져 있어 포인터를 따라갈 때마다 캐시 미스가 잦습니다."},
  {"id":"sc-cs-39","cat":"CS","level":"심화","q":"URL 입력부터 Django가 DB까지 응답하는 전체 경로를 OS와 네트워크 용어를 섞어 설명해 주세요.","a":"클라이언트가 DNS로 IP를 얻고 TCP 3-way handshake로 소켓을 맺은 뒤 TLS 핸드셰이크로 암호화 채널을 만듭니다. 요청이 Nginx(L7 리버스 프록시)에 도착해 TLS 종료 후 Gunicorn으로 프록시되고, OS가 소켓에서 데이터를 읽어(시스템 콜) 워커 프로세스가 Django에 전달합니다. Django가 ORM으로 다시 DB와 소켓 연결을 맺어 쿼리를 보내고, 결과를 받아 응답을 직렬화해 같은 경로를 역으로 돌려보냅니다. 즉 DNS·TCP·TLS·HTTP(네트워크)와 소켓·시스템콜·워커 프로세스(OS)가 한 흐름으로 엮입니다."},
  {"id":"sc-cs-40","cat":"CS","level":"심화","q":"고동시성 서버에서 epoll 같은 멀티플렉싱과 다수 스레드 방식 중 무엇이 유리하며 그 이유는 무엇인가요(C10K)?","a":"수만 개 동시 연결(C10K)에서는 연결마다 스레드를 두면 메모리와 컨텍스트 스위칭 비용이 폭증합니다. epoll 같은 I/O 멀티플렉싱은 한(또는 소수) 스레드가 이벤트 루프로 준비된 소켓만 골라 처리하므로, 대부분 대기 상태인 다수 연결을 적은 자원으로 효율적으로 다룹니다. 그래서 I/O 바운드 고동시성에는 이벤트 기반 멀티플렉싱이 유리합니다."},
  {"id":"sc-arch-1","cat":"ARCH","level":"기본","q":"SRP에서 말하는 '책임'이란 무엇이고, '변경의 이유는 하나'라는 표현을 actor 개념으로 어떻게 설명하시겠어요?","a":"SRP의 책임은 '변경을 요구하는 이유(actor)'를 뜻합니다. 한 클래스가 회계팀·운영팀 등 서로 다른 actor의 요구로 동시에 바뀌어야 한다면 책임이 둘 이상 섞인 것입니다. 즉 '한 가지 일을 한다'가 아니라 '한 종류의 변경 이유에만 반응한다'가 핵심이고, actor가 다르면 클래스를 분리해 한쪽 변경이 다른 쪽을 깨지 않게 합니다."},
  {"id":"sc-arch-2","cat":"ARCH","level":"중급","q":"DIP와 DI의 차이는 무엇이며, Spring에는 있는데 Django에는 없는 것은 무엇인가요?","a":"DIP는 '고수준 모듈이 저수준 구현이 아니라 추상(인터페이스)에 의존한다'는 설계 원칙이고, DI는 그 의존 객체를 외부에서 주입하는 구현 기법입니다. Spring은 IoC 컨테이너가 @Autowired로 DI를 자동화하지만, Django는 DI 컨테이너가 없어 생성자 주입·팩토리·settings 기반 주입으로 직접 와이어링합니다. 원칙(DIP)은 동일하게 적용하되 주입 메커니즘만 수동으로 만든다는 차이입니다."},
  {"id":"sc-arch-3","cat":"ARCH","level":"중급","q":"구현체가 하나뿐인데도 인터페이스를 두는 것이 정당한 경우와, 반대로 과설계가 되는 경우를 구분해 주세요.","a":"테스트에서 fake/mock으로 대체해야 하거나, 외부 시스템(DB·결제 PG)처럼 교체·격리가 예견되는 경계(아웃바운드 포트)라면 구현체가 하나여도 인터페이스가 정당합니다. 반대로 변하지 않을 내부 로직에 '혹시 몰라서' 인터페이스를 두면 YAGNI 위반의 과설계입니다. 판단 기준은 '실제로 다른 구현이 필요하거나 격리 이득이 있는가'입니다."},
  {"id":"sc-arch-4","cat":"ARCH","level":"기본","q":"전략(Strategy) 패턴은 어떤 설계 원칙을 실현하나요?","a":"전략 패턴은 알고리즘을 인터페이스 뒤로 캡슐화해 새 전략 추가 시 기존 코드를 수정하지 않게 하므로 OCP(개방-폐쇄)를 실현하고, 클라이언트가 구체 구현이 아닌 추상에 의존하게 만들어 DIP도 만족합니다. 결제수단별 if-else를 전략 객체로 바꾸면 분기 추가가 클래스 추가로 바뀌는 것이 대표 예입니다."},
  {"id":"sc-arch-5","cat":"ARCH","level":"중급","q":"DRY를 잘못 적용해서 오히려 결합도가 올라간 사례를 들어 설명해 주세요.","a":"우연히 같아 보이는 코드(우연한 중복)를 억지로 한 함수/모듈로 합치면, 서로 다른 이유로 변해야 하는 두 호출처가 하나의 추상에 묶여 한쪽 요구가 다른 쪽을 깨뜨립니다. DRY는 '본질적 중복(같은 지식의 단일 출처)'에만 적용해야 하며, 우연한 중복은 차라리 중복을 허용하는 편이 결합도를 낮춥니다."},
  {"id":"sc-arch-6","cat":"ARCH","level":"중급","q":"레이어드 아키텍처는 의존 방향이 단방향인데도 왜 도메인이 DB에 의존하게 되나요?","a":"호출 방향은 Service→Repository로 단방향이지만, Service가 ORM 엔티티(영속성 모델)를 그대로 다루기 때문에 컴파일/소스 수준의 의존이 도메인→영속성으로 흐릅니다. 즉 도메인 규칙이 ORM 클래스에 결합되어 DB/프레임워크가 바뀌면 도메인도 흔들립니다. 헥사고날은 의존성 역전으로 영속성이 도메인을 향하게 만들어 이를 끊습니다."},
  {"id":"sc-arch-7","cat":"ARCH","level":"중급","q":"Anemic Domain Model이 안티패턴으로 불리는 이유와, 그래도 정당한 경우는 언제인가요?","a":"데이터(엔티티)는 게터/세터만 갖고 로직이 전부 Service로 빠지면 캡슐화가 깨지고 불변식이 여러 곳에 흩어져 일관성을 잃기 때문에 안티패턴이라 불립니다. 다만 도메인 규칙이 거의 없는 단순 CRUD나 트랜잭션 스크립트로 충분한 경우에는 빈약한 모델 + Service가 더 단순하고 적절합니다. 모든 프로젝트에 도메인 모델이 답은 아닙니다."},
  {"id":"sc-arch-8","cat":"ARCH","level":"심화","q":"도메인 로직을 DB 없이 단위 테스트하지 못하게 만드는 구조적 원인은 무엇인가요?","a":"도메인 객체가 ORM 모델을 상속하거나 직접 사용하면, 객체 생성·조회·검증이 DB 세션·쿼리에 묶여 테스트마다 실제 DB가 필요해집니다. 원인은 도메인과 영속성이 한 클래스에 섞인 결합입니다. 도메인을 순수 객체(dataclass)로 분리하고 Repository 포트로 영속성을 밀어내면 도메인 테스트가 DB 없이 인메모리로 돌아갑니다."},
  {"id":"sc-arch-9","cat":"ARCH","level":"중급","q":"Django의 MTV 구조가 fat model/fat view를 유도하는 방식과 완화책은 무엇인가요?","a":"Django는 models가 ORM과 도메인 로직을 겸하고, views가 컨트롤러와 비즈니스 로직을 겸하며, serializers가 DTO와 검증을 겸하도록 유도해 로직이 model·view로 비대해집니다. 완화책은 의도적으로 service layer(애플리케이션 서비스)를 도입해 조율·트랜잭션을 모으고, 도메인 규칙은 도메인 객체로, 형식 검증은 serializer로 분리하는 것입니다."},
  {"id":"sc-arch-10","cat":"ARCH","level":"심화","q":"모든 프로젝트에 헥사고날/DDD를 쓰지 않는 이유와, 도입 여부의 판단 기준은 무엇인가요?","a":"포트/어댑터·도메인 분리는 보일러플레이트와 매핑 비용을 늘리므로, 도메인 복잡도가 낮은 단순 CRUD에는 트랜잭션 스크립트가 더 빠르고 명확합니다. 판단 기준은 도메인 규칙·불변식의 복잡도, 변경 빈도, 외부 시스템 격리·테스트 필요성입니다. 핵심 도메인이 복잡할 때만 비용을 정당화하고, 그 외에는 단순 구조를 택합니다."},
  {"id":"sc-arch-11","cat":"ARCH","level":"중급","q":"헥사고날에서 인바운드 포트와 아웃바운드 포트는 각각 무엇이고 누가 구현하나요?","a":"인바운드 포트는 유스케이스 인터페이스로 애플리케이션 서비스가 구현하고, 외부(웹 컨트롤러 등 인바운드 어댑터)가 이를 호출합니다. 아웃바운드 포트는 저장소·외부 API 같은 의존성의 인터페이스로 도메인/애플리케이션이 정의하지만, 구현은 바깥의 아웃바운드 어댑터(ORM repo, HTTP 클라이언트)가 맡습니다. 양쪽 모두 의존성은 항상 안쪽(도메인)을 향합니다."},
  {"id":"sc-arch-12","cat":"ARCH","level":"심화","q":"도메인 모델과 ORM 모델을 분리할 때의 득과 실은 무엇인가요?","a":"득은 도메인이 영속성에서 자유로워져 DB 없이 단위 테스트가 가능하고, 불변식·캡슐화를 ORM 제약과 무관하게 표현할 수 있다는 점입니다. 실은 도메인↔ORM 매핑(to_domain/to_orm) 코드가 늘고 lazy loading 등 ORM 편의를 일부 포기한다는 점입니다. 도메인 복잡도가 높을수록 이 분리 비용이 정당화됩니다."},
  {"id":"sc-arch-13","cat":"ARCH","level":"중급","q":"애플리케이션 서비스와 도메인 서비스의 차이는 무엇이고, 트랜잭션 경계는 어디에 두나요?","a":"애플리케이션 서비스는 유스케이스를 조율(repo 호출·DTO 변환·트랜잭션 관리)하되 도메인 규칙은 갖지 않고, 도메인 서비스는 한 엔티티에 담기 애매한 순수 도메인 규칙만 담습니다. 트랜잭션 경계는 애플리케이션 서비스 단위에 두며, Spring의 @Transactional이 Django에서는 transaction.atomic으로 대응됩니다."},
  {"id":"sc-arch-14","cat":"ARCH","level":"중급","q":"Spring Data JPA Repository와 Django의 수동 Repository는 어떻게 다른가요?","a":"Spring Data JPA는 인터페이스만 선언하면 구현체를 자동 생성해 주지만, Django에는 그런 추상 Repository가 없어 'Repository 인터페이스(ABC) + ORM 구현'을 직접 손으로 작성해 애플리케이션 서비스에 주입해야 합니다. 그래서 Django에서는 포트/어댑터 분리를 명시적으로 코딩해 의존 방향을 직접 통제합니다."},
  {"id":"sc-arch-15","cat":"ARCH","level":"심화","q":"헥사고날 구조에서 DB 없이 도메인 테스트가 가능한 이유를 의존 방향으로 설명해 주세요.","a":"의존성이 항상 안쪽을 향하므로 도메인·애플리케이션은 아웃바운드 포트(인터페이스)에만 의존하고 ORM 구현에는 의존하지 않습니다. 따라서 테스트에서 포트의 인메모리 fake 구현을 주입하면 실제 DB 없이 도메인 로직을 검증할 수 있고, 속도도 크게 빨라집니다. 의존성 역전이 테스트 용이성의 근본 원인입니다."},
  {"id":"sc-arch-16","cat":"ARCH","level":"심화","q":"DRF Serializer는 어느 계층에 두어야 하며, 도메인 검증을 Serializer에 넣으면 무엇이 문제인가요?","a":"Serializer는 웹(인바운드) 어댑터 계층에 가두어 입력 직렬화/역직렬화와 형식 검증만 담당하게 해야 합니다. 도메인 불변식 검증을 Serializer에 넣으면 도메인 규칙이 웹 프레임워크에 결합되어 다른 진입점(배치·이벤트)에서 우회되고 도메인만 단위 테스트하기 어려워집니다. 형식 검증은 Serializer, 불변식은 도메인 안에 두어야 합니다."},
  {"id":"sc-arch-17","cat":"ARCH","level":"기본","q":"엔티티와 값 객체(VO)의 동일성 판단은 어떻게 다르며, VO를 불변으로 두는 이유는 무엇인가요?","a":"엔티티는 식별자(ID)로 동일성을 판단하고 속성이 바뀌어도 같은 객체이며, VO는 식별자가 없고 모든 값이 같으면 같은 것으로 봅니다(Money, Email). VO를 불변(frozen)으로 두는 이유는 공유 시 부작용을 막고 동등성·해시를 안전하게 하기 위함입니다. Java record가 Python의 @dataclass(frozen=True)에 대응됩니다."},
  {"id":"sc-arch-18","cat":"ARCH","level":"심화","q":"애그리거트 경계는 무엇을 기준으로 정하며, '한 트랜잭션에 애그리거트 하나'가 왜 중요한가요?","a":"애그리거트 경계는 함께 지켜야 하는 불변식(일관성 경계)을 기준으로 정하고, 외부는 루트를 통해서만 접근합니다. 한 트랜잭션에서 하나의 애그리거트만 수정하라는 규칙은 락 경합과 트랜잭션 충돌을 줄이고 확장성을 확보하기 위함이며, 여러 애그리거트에 걸친 일관성은 도메인 이벤트로 최종 일관성으로 처리합니다."},
  {"id":"sc-arch-19","cat":"ARCH","level":"중급","q":"애그리거트 간에는 객체 참조 대신 ID로 참조하라는 이유는 무엇인가요?","a":"ID 참조는 애그리거트를 작게 유지하고 경계를 명확히 해, 한 번에 거대한 객체 그래프를 로딩하지 않게 하고 다른 애그리거트를 같은 트랜잭션에서 무심코 수정하는 일을 막습니다. 또 향후 별도 저장소/서비스로 분리(샤딩·MSA)하기도 쉬워집니다. 직접 객체 참조는 경계를 흐리고 트랜잭션·성능 문제를 키웁니다."},
  {"id":"sc-arch-20","cat":"ARCH","level":"중급","q":"도메인 서비스와 애플리케이션 서비스는 어떻게 구분하나요?","a":"도메인 서비스는 특정 엔티티/VO 하나에 두기 애매한 순수 도메인 규칙(예: 여러 애그리거트를 아우르는 계산)을 담고 외부 의존이 없습니다. 애플리케이션 서비스는 유스케이스 조율자로서 repo 조회·트랜잭션·DTO 변환·이벤트 발행을 담당하되 도메인 규칙 자체는 갖지 않습니다. 규칙은 도메인 서비스, 흐름 제어는 애플리케이션 서비스입니다."},
  {"id":"sc-arch-21","cat":"ARCH","level":"심화","q":"도메인 이벤트는 옵저버 패턴과 어떤 관계이며, 커밋 전 발행과 커밋 후 발행의 트레이드오프는 무엇인가요?","a":"도메인 이벤트는 옵저버 패턴의 도메인 버전으로, 발생 사실(OrderPlaced)을 발행하고 핸들러가 느슨하게 반응합니다. 커밋 전 발행은 핸들러를 같은 트랜잭션에 묶어 원자성은 좋지만 트랜잭션이 길어지고 외부 호출 시 위험합니다. 커밋 후 발행이 기본이며 정합성은 좋아지지만 발행-실패로 이벤트 유실 위험이 있어 Transactional Outbox로 보완합니다."},
  {"id":"sc-arch-22","cat":"ARCH","level":"중급","q":"Django signals를 도메인 이벤트로 쓸 때의 장점과 위험은 무엇인가요?","a":"signals는 발신부와 수신부를 분리해 부수효과(포인트 적립 등)를 느슨하게 붙일 수 있다는 장점이 있습니다. 그러나 암묵적으로 연결되어 실행 흐름 추적이 어렵고, 테스트성이 떨어지며, 트랜잭션·실행 순서가 불명확해 남용 시 디버깅이 힘듭니다. 추적성과 테스트성이 중요하면 명시적 이벤트 버스/디스패처를 쓰는 편이 낫습니다."},
  {"id":"sc-arch-23","cat":"ARCH","level":"중급","q":"도메인 불변식 검증과 형식(입력) 검증을 분리해야 하는 이유는 무엇인가요?","a":"형식 검증(필수값·타입·길이)은 입력 경계에서 DRF Serializer가 처리하고, 비즈니스 불변식(합계=라인 합, 잔액≥0 등)은 도메인 객체 안에서 강제해야 합니다. 분리하면 도메인 규칙이 웹 진입점과 무관하게 항상 지켜지고, 어떤 경로로 들어와도 불변식이 깨지지 않으며 도메인만 단위 테스트할 수 있습니다."},
  {"id":"sc-arch-24","cat":"ARCH","level":"중급","q":"바운디드 컨텍스트와 마이크로서비스는 어떤 관계인가요?","a":"바운디드 컨텍스트는 하나의 모델·유비쿼터스 언어가 일관되게 통하는 논리적 경계이고, 마이크로서비스는 그 경계를 물리적 배포 단위로 구현한 것입니다. 즉 컨텍스트 경계가 서비스 분리의 후보 기준이 되지만, 같은 경계를 모듈러 모놀리스의 모듈로 표현할 수도 있습니다. 컨텍스트는 설계 개념, 서비스는 배포 선택입니다."},
  {"id":"sc-arch-25","cat":"ARCH","level":"중급","q":"같은 '회원'이나 '상품'을 컨텍스트마다 다른 모델로 두는 이유와, 단일 모델로 통합할 때의 위험은 무엇인가요?","a":"같은 상품도 주문 컨텍스트에서는 가격·수량, 재고에서는 위치·수량, 카탈로그에서는 설명·이미지가 중요해 의미가 다릅니다. 컨텍스트별로 필요한 측면만 모델링하면 응집도가 높아집니다. 모든 곳을 만족시키는 단일 거대 모델로 통합하면 서로 다른 변경 이유가 한 모델에 얽혀 결합이 폭증하고 어느 팀도 안전하게 못 바꾸게 됩니다."},
  {"id":"sc-arch-26","cat":"ARCH","level":"심화","q":"ACL(Anti-Corruption Layer)은 무엇을 막아 주며 어디에 위치하나요?","a":"ACL은 외부 시스템/레거시의 모델과 용어가 우리 도메인으로 흘러들어와 오염시키는 것을 막는 번역 계층입니다. 외부(예: PG 결제 응답)를 받아 우리 도메인 개념으로 변환해, 외부 스키마 변경이 도메인까지 번지지 않게 합니다. 위치는 컨텍스트 경계, 즉 외부와 접하는 우리 쪽 어댑터에 둡니다."},
  {"id":"sc-arch-27","cat":"ARCH","level":"중급","q":"서브도메인을 Core/Supporting/Generic으로 나눌 때 노력을 어떻게 배분하나요?","a":"Core(핵심 경쟁력)에 최고의 인력과 정교한 DDD 설계를 집중하고, Supporting은 적당한 자체 구현, Generic(인증·결제·메일 등 일반 기능)은 가능하면 사올(buy)·기존 솔루션을 씁니다. 즉 build vs buy 판단의 기준이며, 모든 영역에 동일한 설계 노력을 쏟지 않는 것이 핵심입니다."},
  {"id":"sc-arch-28","cat":"ARCH","level":"심화","q":"모놀리식 우선과 MSA 우선 중 무엇을 택해야 하며, 성급한 MSA의 위험은 무엇인가요?","a":"경계가 아직 불확실한 초기에는 모놀리식(또는 모듈러 모놀리스) 우선이 일반적으로 안전합니다. 경계를 잘못 그은 채 MSA로 가면 네트워크 호출·분산 트랜잭션·운영 복잡도가 폭증하고 잘못된 서비스 경계를 되돌리기 매우 어렵기 때문입니다. 도메인 경계가 검증되고 조직·확장 요구가 분명해질 때 컨텍스트 단위로 분리하는 것이 안전합니다."},
  {"id":"sc-arch-29","cat":"ARCH","level":"중급","q":"Django에서 바운디드 컨텍스트를 어떻게 표현하고, 앱 간 결합은 어떻게 끊나요?","a":"Django app을 컨텍스트 경계로 삼아 컨텍스트별로 app을 분리합니다. 앱 간에 서로의 ORM 모델을 직접 import하면 결합이 생기므로, 공개 인터페이스(서비스 함수)나 도메인 이벤트를 통해서만 상호작용하게 합니다. 이렇게 하면 앱 경계가 명확해지고 나중에 별도 서비스로 분리하기도 쉬워집니다."},
  {"id":"sc-arch-30","cat":"ARCH","level":"기본","q":"유비쿼터스 언어가 깨지면 어떤 문제가 생기나요?","a":"개발자·도메인 전문가·코드가 같은 용어를 다르게 쓰면 소통 비용이 늘고 요구사항이 코드로 잘못 번역되어 버그가 됩니다. 코드의 클래스/메서드 이름과 현업 용어가 어긋나면 의도 파악이 어려워지고 변경이 위험해집니다. 그래서 컨텍스트 안에서 용어 사전을 맞추고 코드 이름을 그 언어와 일치시켜야 합니다."},
  {"id":"sc-arch-31","cat":"ARCH","level":"심화","q":"분산 트랜잭션에서 2PC 대신 SAGA를 쓰는 이유와, 코레오그래피와 오케스트레이션의 차이는 무엇인가요?","a":"2PC는 모든 참가자를 락으로 묶어 가용성·성능이 떨어지고 코디네이터 장애에 취약해 마이크로서비스에 부적합합니다. SAGA는 로컬 트랜잭션의 연쇄로 처리하고 실패 시 보상 트랜잭션으로 되돌려 최종 일관성을 달성합니다. 코레오그래피는 각 서비스가 이벤트로 자율 반응(중앙 없음)하고, 오케스트레이션은 중앙 오케스트레이터가 단계를 지시해 추적·제어가 쉽습니다."},
  {"id":"sc-arch-32","cat":"ARCH","level":"심화","q":"이중 쓰기(dual write) 문제는 무엇이며 Transactional Outbox로 어떻게 해결하나요?","a":"DB 저장과 메시지 발행을 별도로 하면, 하나는 성공하고 다른 하나가 실패해 상태와 이벤트가 어긋나는 이중 쓰기 문제가 생깁니다. Outbox는 같은 로컬 트랜잭션(transaction.atomic) 안에서 비즈니스 데이터와 함께 outbox 테이블에 이벤트를 적재하고, 별도 폴러/릴레이(Celery beat 등)가 이를 읽어 발행합니다. 발행은 at-least-once가 되므로 컨슈머는 멱등해야 합니다."},
  {"id":"sc-arch-33","cat":"ARCH","level":"심화","q":"메시지 시스템에서 exactly-once가 어려운 이유와, 컨슈머 멱등성으로 어떻게 대응하나요?","a":"네트워크·재시도·장애로 메시지는 중복 전달될 수 있어 진정한 exactly-once 전달은 사실상 어렵고, 보통 at-least-once를 택합니다. 대신 컨슈머를 멱등하게 만들어 같은 메시지를 여러 번 처리해도 결과가 한 번 처리한 것과 같게 합니다. 처리한 메시지 ID를 유니크 제약/처리이력으로 기록해 중복을 걸러내는 방식이 대표적입니다."},
  {"id":"sc-arch-34","cat":"ARCH","level":"심화","q":"비멱등한 POST 결제에 멱등성을 어떻게 구현하며, 무엇을 저장/제약으로 거나요?","a":"클라이언트가 Idempotency-Key를 보내고 서버는 그 키를 유니크 제약이 걸린 테이블에 결과와 함께 저장합니다. 같은 키로 두 번째 요청이 오면 새로 처리하지 않고 기존 결과를 반환합니다. GET/PUT/DELETE는 본질적으로 멱등이라 키가 필요 없지만, POST처럼 부수효과를 만드는 요청에는 키로 따닥/중복 결제를 막습니다. DB의 unique 제약이 동시성 상황에서도 단일 처리를 보장합니다."},
  {"id":"sc-arch-35","cat":"ARCH","level":"중급","q":"CQRS와 이벤트 소싱은 어떤 이점이 있고, 단순 CRUD에는 왜 과한가요?","a":"CQRS는 읽기·쓰기 모델을 분리해 각각 최적화할 수 있고, 이벤트 소싱은 상태 변화를 이벤트로 저장해 완전한 감사 이력과 상태 재구성을 제공합니다. 그러나 모델 이중화·최종 일관성·이벤트 버전 관리 등 복잡도가 크게 늘어, 도메인이 단순하고 감사·확장 요구가 없는 CRUD에서는 과한 오버엔지니어링입니다. 복잡한 핵심 도메인에 선택적으로 적용합니다."},
  {"id":"sc-arch-36","cat":"ARCH","level":"심화","q":"캐시 스탬피드(thundering herd)는 무엇이고 캐시 무효화가 어려운 이유는 무엇인가요?","a":"인기 키가 동시에 만료되면 다수 요청이 한꺼번에 DB로 몰려 부하가 폭증하는 것이 스탬피드입니다. TTL 지터로 만료 시점을 분산하고, single-flight(한 요청만 재계산, 나머지는 대기)나 사전 갱신으로 막습니다. 무효화가 어려운 이유는 데이터 변경 시 어떤 키들이 영향받는지 추적·정확히 비우기가 까다롭고, 무효화 누락 시 stale 데이터가 남기 때문입니다."},
  {"id":"sc-arch-37","cat":"ARCH","level":"심화","q":"서킷 브레이커의 3가지 상태를 설명하고, 재시도와 멱등성을 함께 고려해야 하는 이유를 말해 주세요.","a":"Closed는 정상 통과, 실패율이 임계치를 넘으면 Open으로 전환해 일정 시간 호출을 즉시 차단(빠른 실패)하고, 타임아웃 후 Half-Open에서 소수 요청으로 회복 여부를 탐색해 성공하면 Closed로 복귀합니다. 재시도(지수 백오프)는 회복에 유용하지만 부수효과가 있는 호출을 중복 실행할 수 있으므로, 대상이 멱등할 때만 안전합니다. 그래서 재시도와 멱등성을 함께 설계합니다."},
  {"id":"sc-arch-38","cat":"ARCH","level":"중급","q":"하위호환을 깨지 않는 API 진화 방법과 버저닝 방식들의 장단점은 무엇인가요?","a":"필드 추가는 옵셔널로, 기존 필드 의미·삭제는 피하고 새 버전으로 분리하는 식으로 진화시킵니다. 버저닝은 URI(/v1/, 명확하지만 URL 오염), 헤더, 미디어타입(Accept) 방식이 있으며 각각 가시성과 캐시·라우팅 편의에서 트레이드오프가 있습니다. DRF는 이들 버저닝을 지원하며, 핵심은 클라이언트를 깨지 않으면서 점진적으로 마이그레이션할 경로를 제공하는 것입니다."},
  {"id":"sc-arch-39","cat":"ARCH","level":"심화","q":"분산 시스템에서 한 요청이 여러 서비스를 거칠 때 장애를 어떻게 추적하나요?","a":"correlation ID(또는 trace ID)를 요청 시작점에서 부여해 모든 로그와 다운스트림 호출에 전파하면 흩어진 로그를 한 요청으로 묶을 수 있습니다. 분산 트레이싱(trace/span, OpenTelemetry)으로 서비스 간 호출의 인과·지연을 시각화하고, 구조화 로깅과 RED/USE 메트릭을 함께 보아 병목·실패 지점을 짚습니다. 관측성(로그·메트릭·트레이스) 3축이 분산 장애 진단의 기반입니다."},
  {"id":"sc-py-1","cat":"PY","level":"중급","q":"Python의 GIL이 무엇이고, CPU 바운드와 I/O 바운드 작업에서 멀티스레딩의 효과가 어떻게 달라지나요?","a":"GIL(Global Interpreter Lock)은 CPython에서 한 시점에 하나의 스레드만 바이트코드를 실행하도록 강제하는 락입니다. 그래서 CPU 바운드 작업은 스레드를 늘려도 병렬화가 안 돼 multiprocessing(별도 프로세스, 메모리 분리)으로 풀어야 하고, I/O 바운드는 대기 중 GIL이 해제되므로 threading이나 asyncio가 유효합니다. Java는 진짜 멀티스레드라 이 제약이 없다는 점이 큰 차이이고, Python 3.13의 free-threaded(no-GIL) 빌드가 실험적으로 나온 상태입니다."},
  {"id":"sc-py-2","cat":"PY","level":"중급","q":"Python에서 가변 기본 인자(def f(x=[]))가 왜 버그를 일으키고, 올바른 패턴은 무엇인가요?","a":"기본 인자는 함수 정의 시점에 한 번만 평가되어 같은 리스트 객체가 호출 간 공유되기 때문에, 누적되어 의도치 않은 상태가 남습니다. 올바른 패턴은 기본값을 None으로 두고 함수 본문에서 x = x or [] 또는 if x is None: x = [] 로 매 호출마다 새 객체를 생성하는 것입니다. 불변 기본값(숫자·문자열·튜플)은 안전합니다."},
  {"id":"sc-py-3","cat":"PY","level":"중급","q":"데코레이터를 직접 구현한다면 어떻게 만들고, functools.wraps가 왜 필요한가요?","a":"데코레이터는 함수를 인자로 받아 감싼 새 함수를 반환하는 일급 함수/클로저입니다. wrapper 안에서 전후 처리를 하고 원본을 호출하면 되는데, 그냥 감싸면 __name__·__doc__ 같은 메타데이터가 wrapper 것으로 바뀝니다. functools.wraps를 wrapper에 붙이면 원본 함수의 메타데이터가 보존되어 디버깅·문서화·인트로스펙션이 정상 동작합니다. 횡단 관심사를 분리한다는 점에서 Spring AOP나 @Transactional과 발상이 같습니다."},
  {"id":"sc-py-4","cat":"PY","level":"기본","q":"Python의 덕 타이핑은 Java 인터페이스 기반 다형성과 어떻게 다른가요?","a":"덕 타이핑은 객체가 어떤 타입인지가 아니라 필요한 메서드·속성을 갖췄는지로 동작하는 방식이라, 명시적 구현 선언(implements) 없이도 같은 인터페이스처럼 쓰입니다. Java는 인터페이스를 구현해야 다형성이 성립하지만 Python은 런타임에 호출 가능하면 통과합니다. 정적 검증이 필요하면 typing.Protocol로 구조적 서브타이핑을 선언해 mypy로 확인할 수 있습니다."},
  {"id":"sc-py-5","cat":"PY","level":"기본","q":"리스트 컴프리헨션과 제너레이터 표현식의 차이는 무엇이고 언제 무엇을 쓰나요?","a":"리스트 컴프리헨션은 즉시 전체 리스트를 메모리에 만들고, 제너레이터는 지연 평가로 요청 시 하나씩 생성해 메모리를 거의 안 씁니다. 대용량을 한 번 순회만 하거나 스트리밍할 때는 제너레이터가 유리하고, 여러 번 재사용하거나 인덱싱·len이 필요하면 리스트가 낫습니다. getsizeof로 비교하면 메모리 차이가 확연합니다."},
  {"id":"sc-py-6","cat":"PY","level":"중급","q":"select_related와 prefetch_related의 차이는 무엇이고, 각각 어떤 SQL을 생성하나요?","a":"select_related는 FK·1:1 관계를 JOIN으로 한 번에 가져와 단일 쿼리로 끝내고, prefetch_related는 M:N·역참조 관계를 별도 쿼리로 가져와 파이썬 메모리에서 조인합니다. 즉 정방향 단일 관계는 select_related, 다대다·여러 행이 딸린 관계는 prefetch_related가 맞습니다. JPA의 fetch join이 select_related에 대응하고, 둘 다 N+1을 제거하는 핵심 도구입니다."},
  {"id":"sc-py-7","cat":"PY","level":"중급","q":"Django QuerySet의 지연 평가란 무엇이고 실제 쿼리는 언제 실행되나요?","a":"QuerySet은 정의·필터·체이닝 시점에는 SQL을 날리지 않고 평가가 필요한 순간에 실행됩니다. 구체적으로 순회(iteration), 슬라이싱(스텝 포함), list()·len()·bool()·repr(), 캐시되지 않은 반복 접근 등에서 평가됩니다. 덕분에 쿼리를 조합해 최종 한 번만 보낼 수 있지만, 같은 QuerySet을 반복 평가하면 쿼리가 중복될 수 있어 주의해야 합니다."},
  {"id":"sc-py-8","cat":"PY","level":"중급","q":"Spring의 @Transactional과 Django transaction.atomic의 롤백 동작은 어떻게 대응되나요?","a":"둘 다 블록 내 예외 발생 시 커밋을 막고 롤백하는 트랜잭션 경계를 만듭니다. transaction.atomic은 데코레이터/컨텍스트 매니저로 쓰고 중첩 시 savepoint로 부분 롤백을 지원하며, ATOMIC_REQUESTS로 요청 단위 트랜잭션도 걸 수 있습니다. 큰 차이는 JPA는 영속성 컨텍스트(1차 캐시·dirty checking·flush)가 있어 변경이 자동 감지되지만, Django ORM은 1차 캐시·자동 dirty checking이 없어 save()를 명시 호출해야 한다는 점입니다."},
  {"id":"sc-py-9","cat":"PY","level":"심화","q":"makemigrations와 migrate의 차이는 무엇이고, 무중단으로 컬럼을 추가하려면 어떻게 하나요?","a":"makemigrations는 모델 변경을 감지해 마이그레이션 파일(변경 명세)을 생성만 하고, migrate는 그 파일을 실제 DB에 적용합니다. 무중단 컬럼 추가는 null 허용 또는 DEFAULT가 있는 컬럼으로 먼저 추가해 기존 행과 구버전 코드가 깨지지 않게 하고, 데이터 백필 후 신버전 배포, 마지막에 NOT NULL·제약을 거는 단계적(expand-contract) 방식을 씁니다. Flyway/Liquibase의 버전드 마이그레이션과 같은 역할이고 RunPython으로 데이터 마이그레이션을 끼울 수 있습니다."},
  {"id":"sc-py-10","cat":"PY","level":"심화","q":"Django의 F() 표현식이 동시성 환경에서 안전한 이유는 무엇인가요?","a":"F()는 값을 파이썬으로 읽어와 더한 뒤 다시 쓰는 대신 UPDATE ... SET count = count + 1 형태로 DB에서 직접 연산하게 만들어, read-modify-write 사이의 경합(lost update)을 피합니다. 즉 애플리케이션이 읽은 시점의 낡은 값을 덮어쓰지 않고 DB의 현재 값 기준으로 갱신하므로 동시 증가에 안전합니다. 더 강한 보장이 필요하면 select_for_update로 행 락을 잡거나 낙관적 락(version)을 병행합니다."},
  {"id":"sc-py-11","cat":"PY","level":"중급","q":"Django의 MTV 구조에서 비즈니스 로직은 어디에 두는 게 좋나요(fat model vs service)?","a":"Django는 Spring처럼 명시적 Service 레이어를 강제하지 않고 View가 컨트롤러 역할을 합니다. 도메인 규칙은 fat model(모델 메서드·매니저)에 모으는 게 Django다운 방식이라 재사용·테스트가 쉽고, 여러 모델에 걸친 유스케이스나 외부 연동·트랜잭션 조합이 커지면 별도 service 모듈로 빼서 View를 얇게 유지합니다. View에 로직이 쌓이는 fat view는 피하는 게 핵심입니다."},
  {"id":"sc-py-12","cat":"PY","level":"심화","q":"DRF Serializer의 역직렬화·검증 흐름을 단계별로 설명해 주세요.","a":"is_valid()를 호출하면 run_validation이 돌면서 먼저 각 필드의 to_internal_value와 필드별 validate_<field>가 실행되고, 그다음 객체 전체를 보는 validate()가 교차 검증을 수행합니다. 검증을 통과한 validated_data로 create() 또는 update()가 호출되어 인스턴스를 생성·수정합니다. Spring의 DTO + @Valid + 검증 애너테이션 조합에 대응하며, 필드 검증과 객체 검증의 책임이 나뉘어 있다는 점이 핵심입니다."},
  {"id":"sc-py-13","cat":"PY","level":"중급","q":"DRF에서 APIView, Generic 뷰, ViewSet, ModelViewSet은 각각 언제 선택하나요?","a":"APIView는 HTTP 메서드 핸들러를 직접 다 짜는 가장 낮은 수준으로 동작이 표준 CRUD에서 벗어날 때 씁니다. Generic 뷰는 list/create 같은 패턴을 믹스인으로 제공해 코드를 줄이고, ViewSet은 여러 액션을 한 클래스로 묶어 Router와 결합합니다. ModelViewSet은 표준 CRUD 6액션을 자동 제공해 가장 적은 코드로 끝나므로, 표준 CRUD면 ModelViewSet, 커스텀 동작이 많아질수록 Generic이나 APIView로 내려갑니다."},
  {"id":"sc-py-14","cat":"PY","level":"심화","q":"JWT의 access/refresh 토큰 구조와 토큰 탈취 대응을 세션 방식과 비교해 설명해 주세요.","a":"access는 짧은 수명으로 API 인증에 쓰고 refresh는 길게 두어 access 재발급에 씁니다. JWT는 서버가 상태를 안 들고 검증만 하므로 확장성이 좋지만 만료 전 강제 무효화가 어렵습니다. 그래서 탈취 대응으로 access 수명을 짧게, refresh 회전(rotation)과 블랙리스트를 두어 재사용을 차단합니다. 세션은 서버가 상태를 들고 있어 즉시 로그아웃·무효화가 쉽지만 저장소가 필요하다는 트레이드오프가 있습니다."},
  {"id":"sc-py-15","cat":"PY","level":"심화","q":"DRF 권한에서 has_permission과 has_object_permission은 각각 언제 호출되나요?","a":"has_permission은 뷰 진입 시점에 요청 전체(인증 여부·역할 등)에 대해 먼저 호출되고, has_object_permission은 특정 객체를 조회한 뒤 그 객체 단위 접근(예: 본인 소유 리소스만 수정)을 검사할 때 호출됩니다. 단 has_object_permission은 get_object를 거치는 detail 액션에서만 자동 호출되므로, 목록 필터링은 별도로 queryset에서 처리해야 합니다. Spring의 @PreAuthorize와 메서드/객체 단위 인가에 대응합니다."},
  {"id":"sc-py-16","cat":"PY","level":"중급","q":"오프셋 기반 페이지네이션과 커서 페이지네이션의 차이는 무엇이고, 무한 스크롤에는 무엇이 적합한가요?","a":"OFFSET 방식(PageNumber/LimitOffset)은 뒤 페이지로 갈수록 건너뛴 행을 다 스캔해 느려지고, 페이지 사이에 데이터가 삽입·삭제되면 중복·누락이 생깁니다. CursorPagination은 정렬 키 기준으로 마지막 본 위치 다음을 가져와 깊은 페이지에서도 일정한 성능을 내고 데이터 변동에 안정적입니다. 따라서 무한 스크롤·피드에는 커서가 적합하고, 임의 페이지 점프가 필요한 관리자 화면에는 오프셋이 편합니다."},
  {"id":"sc-py-17","cat":"PY","level":"중급","q":"Spring의 DTO + @Valid와 DRF Serializer는 책임 분담이 어떻게 다른가요?","a":"Spring은 보통 요청 DTO에 @Valid로 입력 검증을 하고 Jackson이 직렬화/역직렬화를, 서비스가 변환·영속을 맡아 책임이 여러 층에 나뉩니다. DRF Serializer는 직렬화·역직렬화·검증·create/update까지 한 객체가 담당해 응집도가 높습니다. 즉 DRF는 입출력 변환과 검증, 영속 로직이 한곳에 모이는 만큼, 비대해지면 비즈니스 로직은 모델·서비스로 분리해 Serializer를 검증·표현 책임으로 좁히는 게 좋습니다."},
  {"id":"sc-py-18","cat":"PY","level":"기본","q":"ModelViewSet이 제공하는 6개 액션은 무엇이고 각각 어떤 HTTP 메서드·URL에 매핑되나요?","a":"list(GET /resources/), create(POST /resources/), retrieve(GET /resources/{id}/), update(PUT /resources/{id}/), partial_update(PATCH /resources/{id}/), destroy(DELETE /resources/{id}/) 6액션입니다. Router가 ViewSet을 등록하면 이 매핑이 자동 생성되고, 추가 동작은 @action 데코레이터로 detail/list 라우트를 덧붙입니다. Spring의 @RestController에서 메서드별 매핑을 직접 쓰는 것을 표준 CRUD에 한해 자동화한 셈입니다."},
  {"id":"sc-py-19","cat":"PY","level":"중급","q":"WSGI와 ASGI의 차이, 그리고 gunicorn과 uvicorn은 각각 어떻게 선택하나요?","a":"WSGI는 동기 요청/응답 표준이고 ASGI는 그 위에 비동기·WebSocket·롱폴링까지 다루도록 확장한 표준입니다. gunicorn은 대표적인 동기 WSGI 서버로 sync worker 모델에 적합하고, uvicorn은 ASGI 서버로 async view나 WebSocket을 처리합니다. 실무에서는 gunicorn에 uvicorn worker를 얹어 프로세스 관리는 gunicorn이, ASGI 처리는 uvicorn이 맡는 조합도 자주 씁니다. 톰캣이 WAS로서 대응되는 자리입니다."},
  {"id":"sc-py-20","cat":"PY","level":"심화","q":"Django ORM은 완전한 비동기인가요? sync_to_async는 언제 필요한가요?","a":"아닙니다. async view는 성숙했지만 ORM은 부분적으로만 비동기(aget/afilter 등)이고 내부 구현이 완전 비동기는 아닙니다. 그래서 async 컨텍스트에서 동기 ORM이나 동기 코드를 호출하려면 sync_to_async로 스레드 풀에 위임해 이벤트 루프를 막지 않게 해야 하고, 반대로 동기에서 async를 부를 땐 async_to_sync를 씁니다. 비동기의 실익은 외부 API 호출 같은 I/O 바운드나 WebSocket에서 큽니다."},
  {"id":"sc-py-21","cat":"PY","level":"심화","q":"Celery를 어떤 작업에 쓰며, 멱등성·재시도·중복 실행 방지는 어떻게 보장하나요?","a":"응답을 늦추면 안 되는 무거운 작업(메일 발송, 채점, LLM 호출, 집계 통계 등)을 브로커를 통해 백그라운드로 빼는 데 씁니다. 재시도는 자동 재시도와 백오프로 일시적 실패를 흡수하되, 재시도·중복 전송으로 같은 작업이 두 번 돌 수 있으므로 태스크를 멱등하게 설계해야 합니다. 멱등키나 unique 제약, 상태 체크(이미 처리됨이면 skip)로 중복을 막고, 예약/주기 작업은 celery beat로 돌립니다. Spring의 @Async/@Scheduled에 대응합니다."},
  {"id":"sc-py-22","cat":"PY","level":"중급","q":"pytest-django에서 테스트 간 DB 격리는 어떻게 보장되고 fixture는 어떻게 쓰나요?","a":"각 테스트를 트랜잭션으로 감싸 끝나면 롤백하는 방식으로 격리해, 테스트마다 깨끗한 상태를 보장하고 속도도 빠릅니다. DB 접근이 필요한 테스트는 @pytest.mark.django_db로 표시하고, fixture로 공통 준비(클라이언트·사용자·데이터)를 주입하며 factory_boy로 모델 인스턴스를 손쉽게 만듭니다. 트랜잭션 롤백으로 안 되는 케이스(여러 커넥션·on_commit)는 transactional 옵션을 써야 합니다. JUnit5 + Mockito 조합에 대응합니다."},
  {"id":"sc-py-23","cat":"PY","level":"중급","q":"Django 애플리케이션 배포 전 점검해야 할 보안 체크리스트는 무엇인가요?","a":"DEBUG=False, ALLOWED_HOSTS 지정, SECRET_KEY를 환경변수로 분리, HTTPS 강제(SECURE_SSL_REDIRECT·HSTS), 보안 쿠키(Secure/HttpOnly/SameSite), CSRF·CORS 설정 점검이 기본입니다. ORM 파라미터화로 SQL 인젝션을 막고 raw 쿼리 사용을 주의하며, settings를 base/dev/prod로 분리합니다. manage.py check --deploy로 누락된 항목을 자동 점검하는 게 핵심 루틴입니다."},
  {"id":"sc-py-24","cat":"PY","level":"심화","q":"GIL이 있는데도 async view가 I/O 바운드에서 이득을 내는 이유는 무엇인가요?","a":"I/O 대기(네트워크·디스크) 동안에는 CPU가 노는데, async는 단일 스레드 이벤트 루프에서 한 작업이 대기에 들어가면 다른 작업으로 전환해 그 빈 시간을 채웁니다. GIL은 CPU 바이트코드 실행을 직렬화할 뿐 I/O 대기를 막지 않으므로, 동시 다수의 외부 API 호출·DB 대기 같은 I/O 바운드에서 처리량이 올라갑니다. 반대로 CPU 바운드는 async로도 GIL을 못 넘어 multiprocessing이 필요합니다."},
  {"id":"sc-py-25","cat":"PY","level":"중급","q":"Spring의 @Async와 @Scheduled는 Django/Python 생태계에서 무엇으로 대응되나요?","a":"@Async로 빼던 비동기 백그라운드 작업은 Celery의 @shared_task(브로커 기반)로, @Scheduled 주기 작업은 celery beat 스케줄로 대응합니다. 간단한 비동기는 Django의 async view나 백그라운드 스레드로도 가능하지만, 재시도·분산·내구성이 필요하면 Celery + 브로커(Redis/RabbitMQ)가 정석입니다. 즉 Spring이 프레임워크 내장으로 주는 것을 Python은 Celery라는 별도 분산 태스크 큐로 푼다는 차이가 있습니다."},
  {"id":"sc-py-26","cat":"PY","level":"심화","q":"제출 저장과 통계 갱신처럼 여러 쓰기가 얽힌 기능에서 트랜잭션 경계를 어디에 두고 왜 그렇게 잡았나요?","a":"제출 저장과 통계 갱신은 하나의 원자적 단위여야 정합성이 맞으므로, 둘을 함께 transaction.atomic으로 감싸 하나가 실패하면 모두 롤백되게 둡니다. 경계는 유스케이스(서비스) 단위로 잡아 너무 넓게(요청 전체) 잡아 락 보유 시간이 길어지지 않게 합니다. 외부 API·LLM 호출 같은 느린 작업은 트랜잭션 밖이나 Celery로 빼서 DB 락을 오래 잡지 않도록 분리하는 게 핵심 판단입니다."},
  {"id":"sc-py-27","cat":"PY","level":"중급","q":"사용자별 데이터 격리는 어느 계층에서 어떻게 보장했나요?","a":"쿼리 계층에서 항상 request.user 기준으로 queryset을 필터링해 다른 사용자 데이터가 애초에 조회되지 않게 하고, 권한 계층에서 has_object_permission으로 객체 단위 소유권을 한 번 더 검증합니다. 즉 필터링(목록 노출 차단)과 객체 권한(직접 접근 차단)을 이중으로 둬야 IDOR 같은 취약점을 막습니다. 관리자는 별도 권한 클래스로 분리합니다."},
  {"id":"sc-py-28","cat":"PY","level":"심화","q":"캡스톤에서 어떤 작업을 Celery로 분리했고, 동기/비동기를 가르는 판단 기준은 무엇이었나요?","a":"응답 지연을 유발하거나 실패해도 재시도가 필요한 작업, 즉 일일 스트릭·정답률 집계, LLM 면접관 API 호출, 무거운 채점을 Celery로 뺐습니다. 판단 기준은 사용자 응답 경로에 반드시 동기로 있어야 하는가, 실행 시간이 긴가, 재시도/스케줄링이 필요한가입니다. 사용자가 즉시 결과를 봐야 하는 짧은 작업은 동기로 두고, 그 외는 비동기로 분리해 응답 시간과 안정성을 확보했습니다."},
  {"id":"sc-py-29","cat":"PY","level":"심화","q":"이 프로젝트를 Spring/JPA로 만들었다면 더 쉬웠을 곳과 더 번거로웠을 곳은 어디인가요?","a":"JPA였다면 영속성 컨텍스트의 dirty checking·1차 캐시 덕에 변경 감지와 flush 제어가 자연스럽고, 명시적 service 레이어와 @Transactional 전파(REQUIRES_NEW 등)가 정형화돼 트랜잭션 조합이 더 깔끔했을 것입니다. 반면 Django는 Admin·마이그레이션·DRF가 기본 제공돼 백오피스와 CRUD API를 훨씬 빠르게 세웠고, 설정·보일러플레이트가 적었습니다. 즉 복잡한 트랜잭션·도메인 모델링은 Spring이, 빠른 API·관리 화면 구축은 Django가 유리합니다."},
  {"id":"sc-py-30","cat":"PY","level":"중급","q":"캡스톤에서 N+1 문제를 어떻게 발견하고 제거했으며 측정값으로 증명할 수 있나요?","a":"django-debug-toolbar와 connection.queries로 목록 API의 쿼리 수를 확인해 행마다 연관 쿼리가 추가로 나가는 N+1을 발견했습니다. FK·1:1은 select_related, M:N·역참조는 prefetch_related로 묶어 쿼리 수를 (1+N)에서 상수로 줄였고, before/after 쿼리 수와 응답시간을 기록해 개선을 정량화했습니다. nplusone으로 회귀를 CI에서 감시하도록 했습니다."},
  {"id":"sc-py-31","cat":"PY","level":"심화","q":"캡스톤에서 내린 가장 큰 기술적 의사결정 하나와 그 트레이드오프를 설명해 주세요.","a":"예를 들어 LLM 면접관 호출을 동기 응답이 아니라 Celery 비동기로 처리하기로 한 결정입니다. 장점은 외부 API 지연·실패가 사용자 요청을 막지 않고 재시도·타임아웃을 통제할 수 있다는 것이고, 트레이드오프는 결과가 즉시 안 와서 폴링/상태 조회 같은 추가 흐름과 브로커(Redis) 운영 복잡도가 생긴다는 점입니다. 사용자 응답 시간과 안정성을 우선해 비동기를 택했고, README에 의사결정 로그로 근거를 남겼습니다."}
);
